// ── CONTENT EXPANSION ─────────────────────────────────────────────────────
// Adds 250+ flashcards and 130+ quiz questions per event
// Appended to existing question banks

// ══════════════════════════════════════════════════════════════════════════
// NUTRITION EXPANSION
// ══════════════════════════════════════════════════════════════════════════
(function expandNutrition(){
  if(!window.QB_NUTRITION) return;
  var fc = window.QB_NUTRITION.flashcards;
  var qz = window.QB_NUTRITION.quiz;

  fc.easy = fc.easy.concat([
    {term:"Calorie",def:"Unit of energy in food — 1 calorie = energy to raise 1g water by 1°C",breakdown:"Food calories are actually kilocalories (kcal). The calorie count on a food label = kcal"},
    {term:"Carbohydrate calories",def:"4 calories per gram of carbohydrate",breakdown:"Carbs are the body's preferred energy source. 1 slice bread ≈ 15g carbs = 60 calories"},
    {term:"Protein calories",def:"4 calories per gram of protein",breakdown:"Same as carbs but protein builds/repairs tissue. 3oz chicken ≈ 21g protein = 84 calories"},
    {term:"Fat calories",def:"9 calories per gram of fat — more than double carbs/protein",breakdown:"Fat is energy-dense. 1 tbsp olive oil = 14g fat = 126 calories. Why fatty foods are calorie-heavy"},
    {term:"Alcohol calories",def:"7 calories per gram of alcohol — between fat and carbs",breakdown:"Alcohol provides calories but no essential nutrients — 'empty calories'"},
    {term:"Simple carbohydrates",def:"Single or double sugar units — digest quickly, rapid blood sugar spike",breakdown:"Glucose, fructose (fruit), lactose (milk), sucrose (table sugar). Fast energy but short-lasting"},
    {term:"Complex carbohydrates",def:"Long chains of sugar units — digest slowly, steady blood sugar",breakdown:"Starch (potatoes, rice) and fiber (vegetables, whole grains). Sustained energy release"},
    {term:"Dietary fiber",def:"Indigestible plant carbohydrate — feeds gut bacteria, aids digestion, lowers cholesterol",breakdown:"Soluble fiber: dissolves in water (oats, beans). Insoluble fiber: doesn't dissolve (wheat bran, vegetables)"},
    {term:"Recommended daily fiber",def:"25g/day for women, 38g/day for men (or 14g per 1000 calories)",breakdown:"Most Americans get only 15g/day. Fiber deficiency linked to constipation, colon cancer risk, heart disease"},
    {term:"Glycemic index (GI)",def:"Rating of how quickly a food raises blood glucose — high GI = fast spike",breakdown:"White bread GI=75, apple GI=36, lentils GI=32. Low GI foods better for sustained energy and diabetes management"},
    {term:"Complete protein",def:"Protein containing all 9 essential amino acids in adequate amounts",breakdown:"Animal sources (meat, eggs, dairy) are complete. Quinoa and soy are plant-based complete proteins"},
    {term:"Incomplete protein",def:"Protein missing or low in one or more essential amino acids",breakdown:"Most plant proteins (beans, rice, nuts) are incomplete but can be combined: rice + beans = complete protein"},
    {term:"Essential amino acids",def:"9 amino acids the body cannot make — must come from food",breakdown:"Histidine, Isoleucine, Leucine, Lysine, Methionine, Phenylalanine, Threonine, Tryptophan, Valine"},
    {term:"Saturated fat",def:"Fat with no double bonds — solid at room temperature — raises LDL cholesterol",breakdown:"Butter, lard, coconut oil, red meat fat. Linked to cardiovascular disease when consumed in excess"},
    {term:"Unsaturated fat",def:"Fat with one or more double bonds — liquid at room temperature — heart-healthy",breakdown:"Monounsaturated (olive oil, avocado) and polyunsaturated (fish, walnuts, flaxseed)"},
    {term:"Trans fat",def:"Artificially hydrogenated unsaturated fat — raises LDL, lowers HDL — worst for heart health",breakdown:"Found in partially hydrogenated oils. FDA banned most trans fats in U.S. food in 2018. Still in some processed foods"},
    {term:"Omega-3 fatty acids",def:"Polyunsaturated fat essential for brain health, reduces inflammation",breakdown:"EPA and DHA from fatty fish (salmon, sardines). ALA from flaxseed, walnuts. Must get from diet"},
    {term:"LDL cholesterol",def:"Low-density lipoprotein — 'bad' cholesterol — deposits in artery walls",breakdown:"LDL < 100 mg/dL optimal. Saturated fat, trans fat, and genetics raise LDL. Target for heart disease prevention"},
    {term:"HDL cholesterol",def:"High-density lipoprotein — 'good' cholesterol — carries LDL back to liver",breakdown:"HDL > 60 mg/dL protective. Exercise raises HDL. Low HDL increases cardiovascular risk"},
    {term:"Fat-soluble vitamins",def:"Vitamins A, D, E, K — stored in fat tissue and liver — can accumulate to toxic levels",breakdown:"Stored long-term so don't need daily intake. Excess supplementation can cause toxicity (especially A and D)"},
    {term:"Water-soluble vitamins",def:"Vitamins C and all B vitamins — not stored, excess excreted in urine",breakdown:"Need regular daily intake. Deficiency develops faster than fat-soluble vitamins. B12 exception: stored in liver"},
    {term:"Vitamin A functions",def:"Vision (especially night vision), immune function, skin and cell growth",breakdown:"Preformed A (retinol) in animal foods. Provitamin A (beta-carotene) in orange/yellow vegetables. Deficiency causes night blindness"},
    {term:"Vitamin C functions",def:"Collagen synthesis, antioxidant, immune support, iron absorption enhancement",breakdown:"Found in citrus, bell peppers, strawberries. Deficiency causes scurvy. Water-soluble — cook gently to preserve"},
    {term:"Vitamin D functions",def:"Calcium absorption, bone health, immune function, muscle function",breakdown:"Synthesized in skin from sunlight. Food sources: fatty fish, fortified dairy. Deficiency: rickets (children), osteomalacia (adults)"},
    {term:"Iron functions",def:"Oxygen transport in hemoglobin, energy metabolism, immune function",breakdown:"Heme iron (meat) absorbed 2-3x better than non-heme iron (plants). Vitamin C enhances non-heme iron absorption"},
    {term:"Calcium functions",def:"Bone and tooth structure, muscle contraction, nerve transmission, blood clotting",breakdown:"99% of body's calcium is in bones/teeth. Dairy, leafy greens, fortified foods. Deficiency leads to osteoporosis"},
    {term:"Sodium functions",def:"Fluid balance, nerve transmission, muscle contraction",breakdown:"DRI: <2300mg/day. Average American gets ~3400mg. Excess raises blood pressure. Kidney disease requires further restriction"},
    {term:"Potassium functions",def:"Fluid balance, heart rhythm, muscle and nerve function — counters sodium",breakdown:"High potassium diet lowers blood pressure. Found in bananas, potatoes, beans, leafy greens"},
    {term:"Dehydration signs",def:"Dark urine, dry mouth, headache, fatigue, dizziness, reduced urine output",breakdown:"2% body weight fluid loss impairs cognitive performance. 5-8% causes serious symptoms. Sports drinks replace electrolytes"},
    {term:"MyPlate",def:"USDA food guide: half plate fruits/vegetables, quarter grains, quarter protein, dairy on side",breakdown:"Replaced the Food Pyramid in 2011. Simple visual guide. Half the plate = produce. No single food is off-limits"},
    {term:"BMI formula",def:"Body Mass Index = weight(kg) / height(m)². Screening tool, not diagnostic",breakdown:"<18.5 underweight; 18.5-24.9 normal; 25-29.9 overweight; ≥30 obese. Doesn't account for muscle mass"},
    {term:"Basal Metabolic Rate (BMR)",def:"Calories burned at complete rest — energy for vital functions (breathing, circulation, cell repair)",breakdown:"Largest component of total daily energy expenditure. Influenced by age, sex, body composition, genetics"},
    {term:"Food label serving size",def:"Reference amount for nutrition information — NOT a recommendation of how much to eat",breakdown:"Calories and all nutrients on label are per serving. If you eat 2 servings, double everything"},
    {term:"% Daily Value (%DV)",def:"How much a nutrient in one serving contributes to a 2000-calorie daily diet",breakdown:"5% DV or less = low in that nutrient. 20% DV or more = high. Use to compare foods and assess diet quality"},
    {term:"Added sugars",def:"Sugars added during food processing — listed separately on Nutrition Facts since 2020",breakdown:"DRI: <10% of calories (50g/day for 2000-cal diet). Natural sugars in fruit and milk not counted as added"},
    {term:"Nutrient density",def:"Amount of nutrients relative to calories — high nutrient density = many nutrients per calorie",breakdown:"Kale is nutrient-dense (many vitamins per calorie). Soda is not (many calories, no nutrients)"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"Nitrogen balance",def:"Difference between nitrogen intake (protein) and nitrogen excretion — positive = muscle building",breakdown:"Positive: intake > excretion (growth, pregnancy, recovery). Negative: excretion > intake (starvation, illness, injury)"},
    {term:"Kwashiorkor",def:"Protein deficiency malnutrition — edema (fluid retention/swelling), growth failure, fatty liver",breakdown:"Distinguished from marasmus by edema. 'Displaced child' in Ghanaian — occurs when child is weaned to starchy diet"},
    {term:"Marasmus",def:"Calorie deficiency malnutrition — severe wasting, muscle and fat loss, no edema",breakdown:"Total energy deficiency unlike kwashiorkor (protein only). Severe weight loss, prominent bones, elderly appearance"},
    {term:"Anemia types in nutrition",def:"Iron-deficiency anemia (most common), B12/folate (megaloblastic), vitamin C deficiency anemia",breakdown:"Iron: microcytic small RBCs. B12/folate: macrocytic large RBCs. All reduce oxygen-carrying capacity"},
    {term:"Folate/Folic acid",def:"B vitamin critical for DNA synthesis and cell division — prevents neural tube defects in pregnancy",breakdown:"Folate = natural form (leafy greens, beans). Folic acid = synthetic (supplements, fortified foods). 400mcg/day recommended; 600mcg pregnant"},
    {term:"Vitamin B12",def:"B vitamin for nerve function, DNA synthesis, red blood cell formation — only in animal foods",breakdown:"Vegans must supplement. Deficiency causes pernicious anemia and nerve damage. Stored in liver (3-5 year supply)"},
    {term:"Thiamin (B1)",def:"B vitamin for carbohydrate metabolism and nerve function",breakdown:"Deficiency causes beriberi (wet: heart failure; dry: nerve damage). Wernicke-Korsakoff syndrome in alcoholics"},
    {term:"Niacin (B3)",def:"B vitamin for energy metabolism — too much causes flushing",breakdown:"Deficiency causes pellagra: Dermatitis, Diarrhea, Dementia, Death (the 4 D's)"},
    {term:"Vitamin K",def:"Fat-soluble vitamin for blood clotting and bone metabolism",breakdown:"K1 (phylloquinone): leafy greens. K2 (menaquinone): fermented foods, synthesized by gut bacteria. Warfarin patients monitor K intake"},
    {term:"Zinc functions",def:"Immune function, wound healing, protein synthesis, taste/smell, DNA synthesis",breakdown:"Oysters highest zinc content. Red meat, poultry, beans, nuts. Deficiency: impaired growth, taste loss, poor wound healing"},
    {term:"Magnesium functions",def:"300+ enzymatic reactions, muscle/nerve function, blood glucose, bone structure, energy production",breakdown:"Found in nuts, seeds, leafy greens, whole grains. Deficiency common, linked to hypertension, diabetes, migraines"},
    {term:"Iodine functions",def:"Thyroid hormone synthesis — regulates metabolism, growth, brain development",breakdown:"Iodized salt solved endemic goiter (enlarged thyroid). Deficiency during pregnancy causes cretinism (intellectual disability)"},
    {term:"Antioxidants",def:"Substances that neutralize free radicals — prevent oxidative cell damage",breakdown:"Free radicals damage DNA, proteins, lipids. Antioxidants: vitamins C, E, beta-carotene, selenium. Found in colorful fruits/vegetables"},
    {term:"Phytochemicals",def:"Non-nutrient plant compounds with health benefits — not essential but protective",breakdown:"Lycopene (tomatoes), flavonoids (berries), glucosinolates (broccoli), resveratrol (red wine). Disease prevention, not just treatment"},
    {term:"Probiotics",def:"Live beneficial microorganisms that colonize the gut — improve digestive and immune health",breakdown:"Lactobacillus and Bifidobacterium common strains. Found in yogurt, kefir, kimchi, sauerkraut. Restore gut flora after antibiotics"},
    {term:"Prebiotics",def:"Non-digestible food components that feed beneficial gut bacteria",breakdown:"Inulin, FOS (fructooligosaccharides). Found in garlic, onions, bananas, asparagus. Distinct from probiotics"},
    {term:"Celiac disease",def:"Autoimmune reaction to gluten — damages small intestine villi — impairs nutrient absorption",breakdown:"Must eliminate wheat, barley, rye. Even oats controversial. 1% of population. Different from wheat allergy or gluten sensitivity"},
    {term:"Lactose intolerance",def:"Inability to digest lactose (milk sugar) due to insufficient lactase enzyme — causes GI symptoms",breakdown:"GI symptoms: bloating, gas, diarrhea. Not an allergy (no immune response). 65% of world population; more common in Asia/Africa"},
    {term:"Food allergy vs intolerance",def:"Allergy: immune response, can be life-threatening. Intolerance: digestive reaction, not life-threatening",breakdown:"Allergy: IgE-mediated, can cause anaphylaxis. Intolerance: enzyme deficiency or chemical sensitivity. Common allergens: FALCOWT SEMP"},
    {term:"Top 9 food allergens",def:"Milk, Eggs, Fish, Shellfish, Tree nuts, Peanuts, Wheat, Soybeans, Sesame",breakdown:"Required on U.S. food labels since FALCPA (2004). Sesame added as 9th in 2023. Together cause 90% of food allergic reactions"},
    {term:"Glycogen",def:"Storage form of glucose in liver and muscles — body's short-term carbohydrate reserve",breakdown:"Liver glycogen: 75-100g (maintains blood glucose). Muscle glycogen: 300-400g (fuel for exercise). Depleted after 12-18 hours fasting"},
    {term:"Insulin function in nutrition",def:"Pancreatic hormone that allows cells to take up glucose from blood — lowers blood sugar",breakdown:"Released after meals. Signals cells to absorb glucose. Also promotes fat and protein storage. Absence/resistance = diabetes"},
    {term:"Glucagon function",def:"Pancreatic hormone that raises blood glucose by stimulating glycogen breakdown and gluconeogenesis",breakdown:"Released when blood glucose falls (fasting, exercise). Counter-regulatory to insulin. Used as emergency treatment for severe hypoglycemia"},
    {term:"Dietary Reference Intakes (DRI)",def:"Framework of nutrient intake standards including RDA, AI, UL, and EAR",breakdown:"RDA: meets needs of 97% of healthy people. AI: adequate intake when RDA unknown. UL: highest daily intake unlikely to cause harm"},
    {term:"Energy balance equation",def:"Weight change = Energy in (food) - Energy out (BMR + activity + thermic effect)",breakdown:"Positive balance = weight gain. Negative balance = weight loss. 3500 kcal deficit ≈ 1 lb fat loss (approximate and contested)"},
    {term:"Thermic effect of food (TEF)",def:"Energy used to digest, absorb, and metabolize food — about 10% of total energy expenditure",breakdown:"Protein has highest TEF (20-30%). Fat lowest (0-3%). Carbs 5-10%. Why high-protein diets slightly boost calorie burning"},
    {term:"Hypertension and diet",def:"DASH diet reduces blood pressure: low sodium, high potassium, calcium, magnesium",breakdown:"DASH = Dietary Approaches to Stop Hypertension. Emphasizes fruits, vegetables, low-fat dairy, whole grains. Limit sodium to 1500-2300mg"},
    {term:"Mediterranean diet",def:"Plant-based diet with olive oil, fish, whole grains, legumes, moderate wine — linked to longevity",breakdown:"Consistently ranked top diet by research. Reduces cardiovascular disease, type 2 diabetes, cognitive decline. UNESCO intangible heritage"},
    {term:"Food security",def:"All people at all times have access to sufficient, safe, and nutritious food",breakdown:"4 dimensions: Availability, Access, Utilization, Stability. Food insecurity affects 800M globally, 30M+ in U.S."},
    {term:"Hunger vs appetite",def:"Hunger: physiological need for food. Appetite: psychological desire for food",breakdown:"Hunger = ghrelin (stomach hormone). Appetite influenced by senses, emotions, habits. Leptin signals satiety to brain"},
  ]);

  fc.hard = fc.hard.concat([
    {term:"Absorptive state (fed state)",def:"Post-meal period — nutrients absorbed, insulin dominant, anabolism occurs",breakdown:"Glucose → glycogen and fat storage. Amino acids → protein synthesis. Lasts 2-4 hours after meal"},
    {term:"Post-absorptive state (fasted state)",def:"Between meals — glycogen breakdown, gluconeogenesis, fat oxidation to maintain blood glucose",breakdown:"Glucagon dominant. Liver releases glucose. After 12-18h glycogen depleted, fat becomes primary fuel"},
    {term:"Ketogenesis",def:"Liver converts fatty acids to ketone bodies during prolonged fasting or carb restriction",breakdown:"Ketones: acetoacetate, beta-hydroxybutyrate, acetone. Brain uses ketones when glucose scarce. Basis of ketogenic diet"},
    {term:"Gluconeogenesis",def:"Synthesis of new glucose from non-carbohydrate precursors (amino acids, glycerol, lactate)",breakdown:"Occurs in liver and kidney. Maintains blood glucose during fasting. Amino acids most important substrate"},
    {term:"Enterohepatic circulation",def:"Recycling of bile salts from intestine back to liver via portal circulation",breakdown:"Bile salts emulsify fat for absorption. 95% recycled, 5% lost in feces. Soluble fiber interrupts this cycle, lowering cholesterol"},
    {term:"VLDL, IDL, LDL, HDL differences",def:"Lipoprotein particles differ in triglyceride/cholesterol ratio and apolipoprotein composition",breakdown:"VLDL: liver-made, triglyceride-rich. IDL: VLDL remnant. LDL: cholesterol-rich, atherogenic. HDL: reverse cholesterol transport"},
    {term:"Phospholipid structure and function",def:"Glycerol + 2 fatty acids + phosphate group — forms cell membrane bilayer",breakdown:"Amphipathic: hydrophilic head, hydrophobic tails. Forms lipid bilayer of all cell membranes. Lecithin is a common dietary phospholipid"},
    {term:"Proteolysis and peptide absorption",def:"Protein digested to amino acids and small peptides — absorbed by specific transporters",breakdown:"Stomach: pepsin. Pancreas: trypsin, chymotrypsin. Small intestine brush border: peptidases. Di/tripeptides absorbed whole"},
    {term:"Vitamin D synthesis pathway",def:"7-dehydrocholesterol → UV light → previtamin D3 → liver (25-OH-D3) → kidney (1,25-OH2-D3 = calcitriol)",breakdown:"Calcitriol is the active hormone form. Kidney conversion impaired in kidney disease — supplementation as active form needed"},
    {term:"Iron absorption regulation",def:"Hepcidin (liver hormone) regulates iron absorption — high iron → high hepcidin → reduced absorption",breakdown:"Hepcidin degrades ferroportin (iron exporter) in enterocytes. Inflammation increases hepcidin → anemia of chronic disease"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"How many calories does 1 gram of carbohydrate provide?",opts:["2","4","7","9"],correct:1,explain:"Carbohydrates provide 4 calories per gram. The same as protein (4 cal/g). Fat provides 9 cal/g and alcohol provides 7 cal/g."},
    {q:"Which nutrient is the body's preferred energy source?",opts:["Fat","Protein","Carbohydrates","Vitamins"],correct:2,explain:"Carbohydrates are the body's preferred energy source because they are most efficiently converted to glucose for immediate use. The brain especially relies on glucose."},
    {q:"What is the recommended daily sodium intake for healthy adults?",opts:["Less than 1000mg","Less than 2300mg","Less than 3500mg","Less than 5000mg"],correct:1,explain:"The recommended daily sodium intake is less than 2300mg for healthy adults. The average American consumes about 3400mg daily, which contributes to hypertension."},
    {q:"Which type of fat is considered most harmful to heart health?",opts:["Monounsaturated fat","Polyunsaturated fat","Saturated fat","Trans fat"],correct:3,explain:"Trans fat (partially hydrogenated oil) is most harmful — it raises LDL (bad) cholesterol AND lowers HDL (good) cholesterol simultaneously. The FDA banned most trans fats in U.S. foods in 2018."},
    {q:"Vitamin D deficiency in children causes which condition?",opts:["Scurvy","Rickets","Pellagra","Beriberi"],correct:1,explain:"Vitamin D deficiency in children causes rickets — soft, weak bones that bow under body weight. In adults, the same deficiency causes osteomalacia (soft bones). Vitamin D is needed for calcium absorption."},
    {q:"Which mineral is most important for bone health?",opts:["Iron","Zinc","Calcium","Magnesium"],correct:2,explain:"Calcium is the most important mineral for bone health — 99% of body calcium is stored in bones and teeth. Adequate calcium throughout life reduces osteoporosis risk. Vitamin D is needed for calcium absorption."},
    {q:"What does MyPlate recommend for half the plate?",opts:["Grains and dairy","Fruits and vegetables","Protein and grains","Fruits and protein"],correct:1,explain:"MyPlate recommends filling half the plate with fruits and vegetables. One quarter should be grains (preferably whole grains) and one quarter protein, with a small dairy serving on the side."},
    {q:"Which vitamin is produced by the skin in sunlight?",opts:["Vitamin A","Vitamin B12","Vitamin C","Vitamin D"],correct:3,explain:"Vitamin D is synthesized in the skin when UV light converts 7-dehydrocholesterol to previtamin D3. This is then activated in the liver and kidneys. Many people are deficient due to limited sun exposure."},
    {q:"A food label shows 20% DV for sodium. This means the food is:",opts:["Low in sodium","Moderate in sodium","High in sodium","Sodium-free"],correct:2,explain:"20% Daily Value or more means the food is HIGH in that nutrient. 5% DV or less = low. The %DV shows how much a nutrient in one serving contributes to a 2000-calorie daily diet."},
    {q:"Omega-3 fatty acids are best obtained from which food source?",opts:["Red meat","White bread","Fatty fish (salmon, sardines)","Vegetable oils"],correct:2,explain:"Fatty fish like salmon, mackerel, sardines, and herring are the best sources of EPA and DHA — the most beneficial forms of omega-3 fatty acids. ALA omega-3 from flaxseed and walnuts must be converted and is less efficiently used."},
    {q:"Which is an example of a complete protein?",opts:["White rice","Black beans","Eggs","Whole wheat bread"],correct:2,explain:"Eggs are a complete protein — they contain all 9 essential amino acids in adequate amounts. Most animal proteins (meat, dairy, eggs) are complete. Most plant proteins are incomplete but can be combined."},
    {q:"What is fiber's primary benefit for digestive health?",opts:["Provides energy for digestion","Adds bulk to stool and feeds beneficial gut bacteria","Breaks down fat in the intestine","Absorbs water-soluble vitamins"],correct:1,explain:"Dietary fiber adds bulk to stool (preventing constipation) and feeds beneficial gut bacteria (prebiotic effect). Soluble fiber also lowers cholesterol and slows glucose absorption."},
    {q:"Which B vitamin is essential for preventing neural tube defects in pregnancy?",opts:["Thiamin (B1)","Niacin (B3)","Folate (B9)","Cobalamin (B12)"],correct:2,explain:"Folate (vitamin B9) is critical for preventing neural tube defects like spina bifida. All women of childbearing age should consume 400mcg daily; pregnant women need 600mcg. Folic acid fortification in grains has reduced neural tube defects dramatically."},
    {q:"What happens to excess water-soluble vitamins in the body?",opts:["Stored in fat tissue","Stored in the liver","Excreted in urine","Converted to fat-soluble vitamins"],correct:2,explain:"Excess water-soluble vitamins (vitamin C and all B vitamins) are excreted in urine since the body cannot store them. This is why they need to be consumed regularly, and why toxicity is rare (unlike fat-soluble vitamins)."},
    {q:"Iron absorption is enhanced by consuming iron with which nutrient?",opts:["Calcium","Vitamin C","Vitamin D","Zinc"],correct:1,explain:"Vitamin C (ascorbic acid) significantly enhances non-heme iron absorption from plant foods. Consuming iron-rich plants with vitamin C sources (citrus juice, bell peppers) can double or triple iron absorption."},
    {q:"What does BMI measure?",opts:["Body fat percentage precisely","Weight relative to height as a screening tool","Muscle mass and bone density","Metabolic rate"],correct:1,explain:"BMI (Body Mass Index) measures weight in kg divided by height in meters squared. It is a SCREENING tool, not a precise health measure. It cannot distinguish between muscle and fat mass."},
    {q:"Which eating pattern is associated with the longest healthy lifespans?",opts:["High-protein diet","Ketogenic diet","Mediterranean diet","Low-fat diet"],correct:2,explain:"The Mediterranean diet — rich in olive oil, fish, vegetables, legumes, and whole grains — is consistently associated with the longest healthy lifespans and lowest rates of heart disease, diabetes, and cognitive decline in research studies."},
    {q:"What is the function of insulin in nutrition?",opts:["Break down stored fat","Allow cells to absorb glucose from the blood","Convert protein to glucose","Signal hunger to the brain"],correct:1,explain:"Insulin is a pancreatic hormone that allows cells to take up glucose from the bloodstream, lowering blood sugar after meals. Type 1 diabetes: no insulin produced. Type 2: cells don't respond properly to insulin."},
    {q:"How many glasses of water does the Institute of Medicine recommend for women daily?",opts:["4 glasses (1 liter)","6 glasses (1.5 liters)","9 glasses (2.2 liters)","13 glasses (3 liters)"],correct:2,explain:"The Institute of Medicine recommends about 9 cups (2.2 liters) of total water daily for women and 13 cups (3 liters) for men. This includes water from all beverages and food (about 20% of water comes from food)."},
    {q:"Which condition results from inadequate protein intake in children?",opts:["Rickets","Kwashiorkor","Scurvy","Pellagra"],correct:1,explain:"Kwashiorkor results from protein deficiency (with adequate calories) in children — characterized by edema (fluid swelling, especially abdominal), growth failure, and fatty liver. Common in developing regions where weaned children receive starchy but protein-poor diets."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"Which lipoprotein is known as 'bad' cholesterol because it deposits cholesterol in artery walls?",opts:["HDL","VLDL","LDL","Chylomicrons"],correct:2,explain:"LDL (Low-Density Lipoprotein) carries cholesterol from the liver to cells and can deposit it in artery walls, forming plaques (atherosclerosis). LDL < 100 mg/dL is optimal. Saturated and trans fats raise LDL."},
    {q:"What is the difference between hunger and appetite?",opts:["They are the same thing","Hunger is physiological; appetite is psychological","Appetite is physiological; hunger is psychological","Hunger lasts longer than appetite"],correct:1,explain:"Hunger is a physiological need for food — triggered by the hormone ghrelin from the stomach. Appetite is a psychological desire for food, influenced by senses, emotions, habits, and environment. You can have appetite without hunger (dessert after a large meal)."},
    {q:"Which vitamin deficiency causes pellagra, characterized by the 4 D's?",opts:["Thiamin (B1)","Riboflavin (B2)","Niacin (B3)","Pyridoxine (B6)"],correct:2,explain:"Niacin (B3) deficiency causes pellagra — Dermatitis, Diarrhea, Dementia, and Death (the 4 D's). Common where corn-based diets dominate without traditional nixtamalization process. Tryptophan can be converted to niacin."},
    {q:"What is the thermic effect of food?",opts:["Temperature increase from eating hot food","Energy used to digest, absorb, and metabolize food (about 10% of calories)","Calories burned during cooking","Heat generated during food storage"],correct:1,explain:"The thermic effect of food (TEF) is the energy required to digest, absorb, and metabolize nutrients — about 10% of total energy intake. Protein has the highest TEF (20-30%), making high-protein diets slightly more metabolically costly."},
    {q:"A patient has iron-deficiency anemia. Which food combination would BEST improve iron absorption?",opts:["Iron supplement with milk","Spinach salad with lemon dressing and vitamin C-rich bell peppers","Red meat with coffee","Iron-fortified cereal with tea"],correct:1,explain:"Spinach (non-heme iron) with bell peppers and lemon dressing provides vitamin C, which dramatically enhances non-heme iron absorption. Coffee and tea contain tannins that INHIBIT iron absorption. Calcium in milk can also reduce iron absorption."},
    {q:"What is glycogen, and where is it stored?",opts:["Fat storage in adipose tissue","Glucose storage in liver and muscles","Protein storage in organ tissue","Cholesterol storage in the gallbladder"],correct:1,explain:"Glycogen is the storage form of glucose in the body — long chains of glucose molecules. About 100g stored in liver (to maintain blood glucose) and 300-400g in muscles (for local energy use). Depleted after 12-18 hours of fasting."},
    {q:"The DASH diet was specifically designed to address which health condition?",opts:["Type 2 diabetes","Osteoporosis","Hypertension (high blood pressure)","Celiac disease"],correct:2,explain:"DASH (Dietary Approaches to Stop Hypertension) was designed to reduce blood pressure without medication. It emphasizes fruits, vegetables, low-fat dairy, whole grains, and limits sodium, saturated fat, and added sugars."},
    {q:"What distinguishes celiac disease from gluten sensitivity?",opts:["Celiac is less severe","Celiac is an autoimmune condition that damages intestinal villi; gluten sensitivity is not","Gluten sensitivity requires stricter avoidance","They are identical conditions"],correct:1,explain:"Celiac disease is an autoimmune reaction where gluten triggers the immune system to attack and damage the small intestine's villi, impairing nutrient absorption. Non-celiac gluten sensitivity causes symptoms without the autoimmune intestinal damage."},
    {q:"Which hormone signals satiety (fullness) to the brain?",opts:["Ghrelin","Glucagon","Leptin","Cortisol"],correct:2,explain:"Leptin is produced by fat cells and signals the brain (hypothalamus) that energy stores are sufficient — suppressing hunger. Ghrelin is the 'hunger hormone' that increases before meals. In obesity, leptin resistance can develop."},
    {q:"What is nutrient density?",opts:["The weight of nutrients in a food","The number of different nutrients in a food","The amount of nutrients relative to a food's calorie content","The concentration of minerals in water"],correct:2,explain:"Nutrient density measures the amount of beneficial nutrients (vitamins, minerals, protein, fiber) per calorie. A highly nutrient-dense food provides many nutrients with few calories (kale, salmon). Low nutrient density = many calories, few nutrients (soda, candy)."},
    {q:"Which macronutrient is most important for wound healing and tissue repair?",opts:["Carbohydrates","Fat","Protein","Vitamins"],correct:2,explain:"Protein is most critical for wound healing — amino acids are the building blocks for new tissue, collagen synthesis, and immune cells. Vitamin C also plays a role in collagen formation. Adequate protein intake is essential after surgery or injury."},
    {q:"What is the main function of bile in fat digestion?",opts:["Break down fat chemically","Emulsify fat into small droplets for enzyme access","Absorb fat-soluble vitamins","Transport fat in the blood"],correct:1,explain:"Bile (produced by the liver, stored in the gallbladder) emulsifies fat — breaking large fat globules into tiny droplets, increasing surface area for pancreatic lipase to work. Bile does not chemically digest fat; lipase does."},
    {q:"Excessive consumption of vitamin A (preformed retinol) can cause:",opts:["Scurvy","Goiter","Toxicity — liver damage, birth defects","Pellagra"],correct:2,explain:"Vitamin A (preformed retinol from animal sources/supplements) is fat-soluble and stored in the liver. Excess causes hypervitaminosis A — liver damage, bone pain, birth defects. Beta-carotene (plant form) cannot cause toxicity as the body regulates conversion."},
    {q:"Which fatty acid type is essential (must be obtained from diet) for human health?",opts:["Saturated fatty acids","Monounsaturated fatty acids","Linoleic acid (omega-6) and alpha-linolenic acid (omega-3)","All fatty acids are essential"],correct:2,explain:"Linoleic acid (omega-6) and alpha-linolenic acid (omega-3) are the two essential fatty acids — the body cannot synthesize them. All other fatty acids can be made from these or from acetyl-CoA."},
    {q:"What is the primary role of the large intestine in nutrition?",opts:["Protein digestion","Fat absorption","Water absorption and gut bacteria fermentation of fiber","Vitamin synthesis"],correct:2,explain:"The large intestine (colon) absorbs water and electrolytes from indigestible food residue. Resident gut bacteria ferment dietary fiber, producing short-chain fatty acids that nourish colonocytes and reduce cancer risk. No significant nutrient absorption occurs here."},
    {q:"A teenage athlete needs more of which nutrient compared to a sedentary peer?",opts:["Fat","Vitamin C","Protein and overall calories","Sodium"],correct:2,explain:"Active teens need more total calories to fuel activity and more protein to support muscle repair and growth. Iron needs also increase for female athletes. Energy needs vary by sport intensity and training volume."},
    {q:"Which condition results from excessive fluoride intake during tooth development?",opts:["Dental caries","Dental fluorosis (white spots/mottling on teeth)","Gingivitis","Enamel erosion from acid"],correct:1,explain:"Dental fluorosis occurs when children ingest too much fluoride during tooth development — causing white spots, streaks, or pitting on permanent teeth. Low levels are cosmetic only. Fluoride in water prevents caries; excess causes fluorosis."},
    {q:"What is the 'thermic effect of food' for protein compared to carbohydrates?",opts:["Lower (0-3%) vs higher (5-10%)","Higher (20-30%) vs lower (5-10%)","The same for both (10%)","Protein has no thermic effect"],correct:1,explain:"Protein has a thermic effect of 20-30% — meaning 20-30% of protein calories are burned just in digestion and metabolism. Carbohydrates have a 5-10% thermic effect. This is one reason high-protein diets may aid weight management."},
    {q:"Which test best assesses long-term blood glucose control over 2-3 months?",opts:["Fasting blood glucose","Oral glucose tolerance test","Hemoglobin A1c (HbA1c)","Random blood glucose"],correct:2,explain:"HbA1c (glycated hemoglobin) reflects average blood glucose over the past 2-3 months — the lifespan of red blood cells. Used to diagnose and monitor diabetes management. Normal: <5.7%; Prediabetes: 5.7-6.4%; Diabetes: ≥6.5%"},
    {q:"What is the role of phytochemicals in nutrition?",opts:["They are essential nutrients like vitamins","Non-essential plant compounds with disease-preventive properties","They replace protein in plant-based diets","They are toxic when consumed in large amounts"],correct:1,explain:"Phytochemicals are non-nutrient plant compounds (lycopene, flavonoids, glucosinolates, etc.) that have health-protective properties but are not nutritionally essential. They function as antioxidants, anti-inflammatory agents, and cancer-protective compounds."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"In nitrogen balance, what does a 'negative nitrogen balance' indicate?",opts:["More nitrogen consumed than excreted — muscle building","More nitrogen excreted than consumed — muscle breakdown","Equal nitrogen in and out — maintenance","Nitrogen being converted to fat"],correct:1,explain:"Negative nitrogen balance means more nitrogen is lost (excreted) than consumed. Since nitrogen comes almost entirely from protein, this indicates net protein breakdown — occurring during starvation, illness, severe injury, or inadequate protein intake."},
    {q:"What is enterohepatic circulation and why does it matter for cholesterol?",opts:["Liver-to-intestine nutrient delivery","Recycling of bile salts from intestine back to liver — soluble fiber interrupts this, lowering cholesterol","The pathway of dietary fat absorption","The portal circulation carrying nutrients from intestine to liver"],correct:1,explain:"Enterohepatic circulation is the recycling of bile salts from the intestine back to the liver via the portal vein — 95% of bile salts are recycled. Soluble fiber binds bile salts in the intestine, interrupting recycling and forcing the liver to use cholesterol to make new bile salts, thus lowering blood cholesterol."},
    {q:"What is gluconeogenesis, and which amino acid is the primary substrate?",opts:["Glucose storage as glycogen; branched-chain amino acids","New glucose synthesis from non-carbohydrate precursors; alanine is the primary amino acid substrate","Fat synthesis from glucose; glutamine","Ketone body synthesis from fatty acids; leucine"],correct:1,explain:"Gluconeogenesis is the synthesis of new glucose from non-carbohydrate precursors (amino acids, glycerol, lactate) primarily in the liver. Alanine from muscle protein breakdown is the most important amino acid substrate during fasting/starvation."},
    {q:"The vitamin D synthesis pathway requires activation in which two organs?",opts:["Stomach and intestine","Liver (25-hydroxylation) and kidney (1-alpha-hydroxylation to active calcitriol)","Pancreas and liver","Skin and small intestine"],correct:1,explain:"Vitamin D synthesis: skin produces cholecalciferol (D3) from UV light. The LIVER adds a hydroxyl group (25-OH-D3/calcidiol). The KIDNEY adds another hydroxyl group to make 1,25-OH2-D3 (calcitriol) — the active hormone form that promotes calcium absorption."},
    {q:"Hepcidin regulates iron homeostasis. Which condition would INCREASE hepcidin secretion?",opts:["Iron deficiency anemia","Hemochromatosis (iron overload) and inflammation","Blood loss and pregnancy","Vegetarian diet"],correct:1,explain:"Hepcidin is the master regulator of iron. High iron levels and inflammation INCREASE hepcidin, which degrades ferroportin (the iron exporter), reducing iron absorption. This explains anemia of chronic disease — inflammation raises hepcidin, blocking iron release even when stores are present."},
  ]);
})();

// ══════════════════════════════════════════════════════════════════════════
// MATH FOR HEALTH CAREERS EXPANSION
// ══════════════════════════════════════════════════════════════════════════
(function expandMath(){
  if(!window.QB_MATH) return;
  var fc = window.QB_MATH.flashcards;
  var qz = window.QB_MATH.quiz;

  fc.easy = fc.easy.concat([
    {term:"Ratio",def:"Comparison of two quantities using division — written as a:b or a/b",breakdown:"A 1:2 ratio of drug to saline means 1 part drug per 2 parts saline. Used for mixing solutions in healthcare"},
    {term:"Proportion",def:"Two equal ratios — used to solve dosage problems: a/b = c/d",breakdown:"If 250mg in 5mL, how much for 375mg? Set up: 250/5 = 375/x → x = 7.5mL"},
    {term:"Percentage",def:"Parts per hundred — converts to decimal by dividing by 100",breakdown:"25% = 25/100 = 0.25. A 5% saline solution has 5g salt per 100mL water"},
    {term:"Metric system base units",def:"Meter (length), Gram (mass), Liter (volume) — decimals based on powers of 10",breakdown:"Healthcare uses metric: mg for drugs, mL for fluids, cm for height. Prefixes: kilo(1000×), centi(1/100), milli(1/1000), micro(1/1,000,000)"},
    {term:"Kilogram to pound conversion",def:"1 kg = 2.2 lbs — used to calculate medication doses based on body weight",breakdown:"Patient weighs 154 lbs → 154 ÷ 2.2 = 70 kg. Drug dose: 5 mg/kg → 70 × 5 = 350 mg total dose"},
    {term:"Celsius to Fahrenheit",def:"°F = (°C × 9/5) + 32 — healthcare uses both temperature scales",breakdown:"37°C × 9/5 = 66.6 + 32 = 98.6°F (normal body temp). Quick mental check: 37°C = 98.6°F, 40°C = 104°F (fever)"},
    {term:"Fahrenheit to Celsius",def:"°C = (°F - 32) × 5/9",breakdown:"Patient temp 102.2°F → (102.2-32) × 5/9 = 70.2 × 5/9 = 39°C. Above 38°C (100.4°F) is fever in adults"},
    {term:"Pulse rate calculation",def:"Count beats in 15 seconds, multiply by 4 — or count 30 sec × 2 for more accuracy",breakdown:"15-sec count: 18 beats × 4 = 72 bpm (normal). 30-sec count: 36 beats × 2 = 72 bpm. Count for 60 sec if irregular rhythm"},
    {term:"Respiratory rate",def:"Count breaths per minute — one breath = one rise and fall of chest",breakdown:"Normal adult: 12-20 breaths/min. Count for 30 seconds × 2. Abnormal if <12 (bradypnea) or >20 (tachypnea)"},
    {term:"Blood pressure reading",def:"Systolic (top number) / Diastolic (bottom number) in mmHg",breakdown:"120/80 mmHg: systolic = pressure during heartbeat, diastolic = pressure between beats. Read the gauge as it falls"},
    {term:"BMI calculation",def:"BMI = weight(kg) ÷ height²(m) — or weight(lbs) × 703 ÷ height²(inches)",breakdown:"70kg ÷ (1.75m)² = 70 ÷ 3.0625 = 22.9 (normal). Categories: <18.5 under, 18.5-24.9 normal, 25-29.9 over, ≥30 obese"},
    {term:"Mean (average)",def:"Sum of all values ÷ number of values",breakdown:"Patient BP readings: 118, 122, 126, 120. Mean = (118+122+126+120) ÷ 4 = 486 ÷ 4 = 121.5 mmHg"},
    {term:"Median",def:"Middle value when data is arranged in order",breakdown:"Data: 68, 72, 74, 76, 88. Median = 74. If even number: average the two middle values. Less affected by extreme outliers than mean"},
    {term:"Mode",def:"Most frequently occurring value in a data set",breakdown:"Heart rates: 68, 72, 72, 74, 72, 80. Mode = 72. A data set can have no mode, one mode, or multiple modes"},
    {term:"Range",def:"Difference between the highest and lowest values in a data set",breakdown:"Blood glucose readings: 85, 92, 104, 118, 145. Range = 145 - 85 = 60 mg/dL. Measures data spread"},
    {term:"Fraction to decimal conversion",def:"Divide numerator by denominator: 3/4 = 3 ÷ 4 = 0.75",breakdown:"Drug concentration: 1/2 strength solution = 0.5 concentration. 3/8 = 0.375. Essential for dosage calculations"},
    {term:"Decimal to percent",def:"Multiply decimal by 100: 0.75 × 100 = 75%",breakdown:"Solution strength: 0.9 = 90% (normal saline is 0.9% NaCl). Survival rate: 0.85 = 85% survival"},
    {term:"Military time (24-hour clock)",def:"Hours 0000-2359, no AM/PM — 1300 = 1:00 PM, 0800 = 8:00 AM",breakdown:"Convert: PM times add 12 (3 PM + 12 = 1500). AM times: 0600 = 6:00 AM. Midnight = 0000 or 2400. Standard in healthcare"},
    {term:"24-hour time conversion",def:"To convert 1 PM onward: add 12. To convert back: subtract 12 if ≥1300",breakdown:"2:30 PM → 1430. 11:45 PM → 2345. 0930 → 9:30 AM. 1630 → 4:30 PM (1630 - 1200 = 4:30)"},
    {term:"Fluid ounces to milliliters",def:"1 fl oz = 29.57 mL (approximately 30 mL)",breakdown:"Patient drinks 8 oz water: 8 × 30 = 240 mL. 1 cup = 8 oz = 240 mL. Used for fluid intake/output records"},
    {term:"Intake and output (I&O)",def:"Measurement of all fluids entering and leaving the body in 24 hours",breakdown:"Input: drinks, IV fluids, tube feeds. Output: urine, wound drainage, vomiting. Normal urine output: 30mL/hr minimum"},
    {term:"Drug concentration",def:"Amount of drug per unit volume — mg/mL or mg/tablet",breakdown:"500 mg in 250 mL = 2 mg/mL concentration. Need 750 mg → 750 ÷ 2 = 375 mL needed"},
    {term:"Dosage formula",def:"Dose needed = (desired dose ÷ dose on hand) × quantity on hand",breakdown:"Need 250mg, have 500mg/tablet → (250÷500) × 1 tab = 0.5 tablet. Need 75mg, have 25mg/5mL → (75÷25)×5 = 15mL"},
    {term:"Drops per minute (IV rate)",def:"gtts/min = (volume in mL × drop factor) ÷ time in minutes",breakdown:"1000mL over 8 hours, 15 gtts/mL factor: (1000 × 15) ÷ 480 min = 15000 ÷ 480 = 31.25 ≈ 31 gtts/min"},
    {term:"Percent error",def:"|(Measured - True) ÷ True| × 100 — measures accuracy of measurement",breakdown:"True weight 70kg, scale reads 71kg: |71-70|/70 × 100 = 1/70 × 100 = 1.43% error. Used in lab quality control"},
    {term:"Body surface area (BSA)",def:"Measurement used for chemotherapy and burn treatment dosing (m²)",breakdown:"BSA used because some drugs distribute based on body size. Mosteller formula: BSA = √(height cm × weight kg ÷ 3600)"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"Dimensional analysis",def:"Method to convert units by multiplying by conversion fractions that equal 1",breakdown:"Convert 2.5 kg to mg: 2.5 kg × (1000g/1kg) × (1000mg/1g) = 2,500,000 mg = 2.5 × 10⁶ mg"},
    {term:"IV flow rate calculation",def:"mL/hour = total volume ÷ total hours for infusion pumps",breakdown:"1 liter over 8 hours = 1000mL ÷ 8h = 125 mL/hr. Adjust if rate changes. Pumps use mL/hr; gravity uses gtts/min"},
    {term:"Pediatric weight-based dosing",def:"Child dose (mg) = adult dose × (child weight kg ÷ 70 kg) OR mg/kg × weight",breakdown:"Drug: 10 mg/kg/day. Child weighs 25 kg → 10 × 25 = 250 mg/day. Always confirm with pharmacy and weight"},
    {term:"Standard deviation",def:"Measure of how spread out data is around the mean — larger SD = more variation",breakdown:"Lab values: SD tells if results are tightly clustered or highly variable. Normal distribution: 68% within 1 SD, 95% within 2 SD"},
    {term:"Percentile",def:"Position in a ranked distribution — 75th percentile = scored higher than 75% of the group",breakdown:"A child's height at 90th percentile: taller than 90% of peers. Used in growth charts. NOT the same as 90% correct"},
    {term:"Caloric needs calculation (Harris-Benedict)",def:"BMR varies by sex, weight, height, age — then multiplied by activity factor",breakdown:"Basic: Women BMR ≈ 655 + (9.6×kg) + (1.8×cm) - (4.7×age). Sedentary: BMR × 1.2. Moderately active: BMR × 1.55"},
    {term:"Concentration percentage calculation",def:"% = (grams of solute ÷ mL of solution) × 100",breakdown:"10g of NaCl in 1000mL = (10÷1000)×100 = 1% solution. Normal saline = 0.9% = 9g NaCl per 1000mL"},
    {term:"Dilution calculation (C1V1=C2V2)",def:"Concentration 1 × Volume 1 = Concentration 2 × Volume 2",breakdown:"Dilute 70% alcohol to 50%: 70 × V1 = 50 × 100mL → V1 = 5000÷70 = 71.4 mL of 70% + 28.6 mL water"},
    {term:"Rounding in healthcare",def:"Medication doses rounded to practical amounts — tablets to nearest half, liquids to nearest 0.1mL",breakdown:"Calculated dose 1.73 tablets → give 1.5 tablets (nearest half). 4.16 mL liquid → give 4.2 mL. NEVER round up significantly"},
    {term:"Scientific notation",def:"Very large or small numbers expressed as a × 10ⁿ",breakdown:"1,000,000 cells = 1 × 10⁶. 0.00025 mg = 2.5 × 10⁻⁴ mg. Microbiology uses scientific notation for bacterial counts"},
    {term:"Absolute risk vs relative risk",def:"Absolute: actual % difference. Relative: ratio of risks between groups",breakdown:"Drug reduces heart attack from 2% to 1%. Absolute risk reduction = 1%. Relative risk reduction = 50%. Headlines often report relative (more impressive)"},
    {term:"Sensitivity and specificity",def:"Sensitivity: ability to identify true positives (catches disease). Specificity: ability to identify true negatives (rules out disease)",breakdown:"High sensitivity: few false negatives (good screening). High specificity: few false positives (good confirmation). Perfect test has both = 100%"},
    {term:"Number needed to treat (NNT)",def:"NNT = 1 ÷ Absolute Risk Reduction — patients needed to treat to prevent one bad outcome",breakdown:"ARR = 5% (0.05): NNT = 1÷0.05 = 20. Must treat 20 patients to prevent 1 event. Lower NNT = more effective treatment"},
    {term:"Apothecary to metric conversion",def:"1 grain = 65 mg, 1 dram = 4 mL, 1 ounce = 30 mL, 1 minim = 0.06 mL",breakdown:"Older prescriptions may use grains. Aspirin 5 grains = 5 × 65mg = 325mg. Most systems now use metric exclusively"},
    {term:"Significant figures in healthcare",def:"Meaningful digits in a measurement — precision matters for dosing",breakdown:"Temperature 98.6°F: 3 significant figures. Drug dose 2.50 mg: 3 sig figs (the zero is significant). Recording more precision than instrument allows is incorrect"},
  ]);

  fc.hard = fc.hard.concat([
    {term:"Pharmacokinetics: first-order kinetics",def:"Drug elimination rate proportional to concentration — constant percentage eliminated per time",breakdown:"Most drugs follow first-order: if half-life = 4hr, 100mg → 50mg (4hr) → 25mg (8hr) → 12.5mg (12hr). Predictable"},
    {term:"Half-life calculation",def:"Time for drug concentration to fall by 50% — 5 half-lives for full elimination",breakdown:"Half-life 6hr: drug given at 0800. By 2000 (12hr/2 half-lives): 25% remains. By 0200 (18hr/3 half-lives): 12.5% remains"},
    {term:"Loading dose vs maintenance dose",def:"Loading: large initial dose to rapidly achieve therapeutic level. Maintenance: smaller doses to sustain level",breakdown:"Loading dose = target concentration × volume of distribution. Given when rapid effect needed (e.g., digoxin, antibiotics)"},
    {term:"Confidence interval interpretation",def:"Range that likely contains the true population value — 95% CI means 95% confidence the true value falls within",breakdown:"BP drug study: mean reduction 5.2 mmHg (95% CI: 3.1-7.3). True effect likely between 3.1 and 7.3 mmHg. If CI includes 0, result not significant"},
    {term:"Pearson correlation coefficient (r)",def:"Measures strength and direction of linear relationship: r ranges from -1 to +1",breakdown:"r = +1: perfect positive. r = -1: perfect negative. r = 0: no relationship. r = 0.8: strong positive correlation. Healthcare research uses r² (variance explained)"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"A patient weighs 176 pounds. What is their weight in kilograms?",opts:["60 kg","80 kg","88 kg","100 kg"],correct:1,explain:"176 lbs ÷ 2.2 = 80 kg. Memorize: divide pounds by 2.2 to get kilograms. This conversion is used constantly for weight-based medication dosing."},
    {q:"Normal body temperature is 37°C. What is this in Fahrenheit?",opts:["96.8°F","98.6°F","100.4°F","102.2°F"],correct:1,explain:"°F = (37 × 9/5) + 32 = (37 × 1.8) + 32 = 66.6 + 32 = 98.6°F. Memorize this pair: 37°C = 98.6°F. A temperature of 40°C = 104°F indicates significant fever."},
    {q:"A nurse counts 18 pulse beats in 15 seconds. What is the pulse rate per minute?",opts:["54 bpm","72 bpm","90 bpm","108 bpm"],correct:1,explain:"18 beats × 4 (to convert 15 seconds to 1 minute) = 72 bpm. Normal adult range is 60-100 bpm. This is the most common clinical pulse counting method."},
    {q:"What time is 2:30 PM in military (24-hour) time?",opts:["0230","1230","1430","2230"],correct:2,explain:"For PM times after 12 PM, add 12: 2:30 PM + 12 = 14:30 = 1430. Morning times stay the same (0800 = 8:00 AM). Midnight = 0000."},
    {q:"A medication order reads 500mg. The tablets on hand are 250mg each. How many tablets should be given?",opts:["0.5 tablet","1 tablet","2 tablets","4 tablets"],correct:2,explain:"Using the dosage formula: desired ÷ on hand × quantity = 500 ÷ 250 × 1 tablet = 2 tablets."},
    {q:"The mean of these five temperatures is: 98.2, 98.6, 99.0, 98.8, 99.4",opts:["98.6°F","98.8°F","99.0°F","98.2°F"],correct:1,explain:"Mean = sum ÷ count = (98.2 + 98.6 + 99.0 + 98.8 + 99.4) ÷ 5 = 494.0 ÷ 5 = 98.8°F."},
    {q:"1 fluid ounce equals approximately how many milliliters?",opts:["10 mL","15 mL","30 mL","60 mL"],correct:2,explain:"1 fluid ounce ≈ 30 mL (exactly 29.57 mL). A standard 8 oz cup = 240 mL. Used for recording oral fluid intake in healthcare settings."},
    {q:"A patient's BMI is 27. Which category does this fall in?",opts:["Underweight","Normal weight","Overweight","Obese"],correct:2,explain:"BMI 25-29.9 = Overweight. BMI categories: <18.5 underweight, 18.5-24.9 normal, 25-29.9 overweight, ≥30 obese. BMI is a screening tool, not a diagnosis."},
    {q:"What percentage is equivalent to the fraction 3/4?",opts:["25%","50%","75%","80%"],correct:2,explain:"3 ÷ 4 = 0.75 = 75%. To convert any fraction to percent: divide numerator by denominator, then multiply by 100."},
    {q:"A patient's blood pressure is recorded as 130/85 mmHg. What is the systolic pressure?",opts:["85 mmHg","130 mmHg","215 mmHg","45 mmHg"],correct:1,explain:"In a blood pressure reading, the TOP number (130) is the systolic pressure — pressure during heart contraction. The BOTTOM number (85) is diastolic — pressure between beats."},
    {q:"What is the median of: 62, 68, 72, 78, 84?",opts:["62","68","72","78"],correct:2,explain:"Median = middle value when arranged in order. The list already has 5 values in order: 62, 68, 72, 78, 84. The middle (3rd) value is 72."},
    {q:"Normal urine output per hour for adults is at least:",opts:["10 mL/hr","30 mL/hr","60 mL/hr","100 mL/hr"],correct:1,explain:"Minimum normal urine output is 30 mL/hr (0.5 mL/kg/hr). Below this indicates possible dehydration, kidney impairment, or poor perfusion. This is a critical clinical monitoring value."},
    {q:"A drug is ordered at 10 mg/kg for a child weighing 30 kg. What total dose is needed?",opts:["30 mg","100 mg","300 mg","3,000 mg"],correct:2,explain:"10 mg/kg × 30 kg = 300 mg total dose. Weight-based dosing is the standard in pediatrics. Always confirm with pharmacy."},
    {q:"How many milligrams are in 1 gram?",opts:["10 mg","100 mg","1,000 mg","10,000 mg"],correct:2,explain:"1 gram = 1,000 milligrams. The prefix 'milli' = 1/1000. So 1g = 1000 mg. 1 kg = 1000 g = 1,000,000 mg. Essential for medication dosing."},
    {q:"What is the range of these pulse readings: 64, 72, 68, 80, 76?",opts:["8","12","16","20"],correct:2,explain:"Range = highest - lowest = 80 - 64 = 16 bpm. Range measures the spread of data. It is simple but sensitive to extreme values."},
    {q:"A patient drinks 6 fluid ounces of juice. How many mL is this?",opts:["60 mL","120 mL","180 mL","240 mL"],correct:2,explain:"6 fl oz × 30 mL/oz = 180 mL. Fluid intake is recorded in mL in healthcare. Always convert ounces to mL for accurate I&O documentation."},
    {q:"What is 15% of 80?",opts:["8","12","15","20"],correct:1,explain:"15% of 80 = 0.15 × 80 = 12. In healthcare: a 15% solution means 15g per 100mL. Percentage calculations are used in drug concentrations and statistics."},
    {q:"Convert 0730 military time to standard time.",opts:["7:30 PM","7:30 AM","12:30 AM","19:30"],correct:1,explain:"Times 0001-1159 in military time convert directly: 0730 = 7:30 AM. Times 1300-2359 subtract 12: 1900 = 7:00 PM. 0000 = midnight."},
    {q:"A patient's temperature is 39.4°C. Convert to Fahrenheit.",opts:["100.4°F","101.4°F","102.9°F","103.9°F"],correct:2,explain:"°F = (39.4 × 9/5) + 32 = (39.4 × 1.8) + 32 = 70.92 + 32 = 102.92°F ≈ 102.9°F. A high fever requiring clinical attention."},
    {q:"What does a proportion allow you to do in healthcare math?",opts:["Add unlike units","Solve for unknown values when ratios are equal","Convert Celsius to Fahrenheit","Calculate BMI"],correct:1,explain:"A proportion states that two ratios are equal (a/b = c/d), allowing you to solve for an unknown value. Essential for dosage calculations: if 500mg is in 10mL, how much liquid for 750mg? Set up 500/10 = 750/x → x = 15 mL."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"An IV is ordered to run 500 mL over 4 hours. The drop factor is 20 gtts/mL. What is the flow rate in gtts/min?",opts:["31 gtts/min","42 gtts/min","10 gtts/min","25 gtts/min"],correct:1,explain:"Formula: (Volume × Drop factor) ÷ Time in minutes. (500 × 20) ÷ 240 minutes = 10,000 ÷ 240 = 41.7 ≈ 42 gtts/min."},
    {q:"A drug has a half-life of 4 hours. A patient receives 200mg at 8 AM. How much remains at 4 PM?",opts:["100 mg","50 mg","25 mg","12.5 mg"],correct:1,explain:"8 AM to 4 PM = 8 hours = 2 half-lives. After 1 half-life (4hr): 100mg. After 2 half-lives (8hr): 50mg. Each half-life reduces amount by 50%."},
    {q:"A child's height is at the 85th percentile. What does this mean?",opts:["The child is 85 cm tall","The child is taller than 85% of peers the same age","The child scored 85% on a growth test","The child needs 85 more cm to reach adult height"],correct:1,explain:"85th percentile means the child is taller than 85% of children the same age and sex. Percentiles describe position within a distribution, not actual measurements or test scores."},
    {q:"A solution is prepared by dissolving 5g of drug in 200mL of water. What is the percentage concentration?",opts:["1%","2.5%","5%","10%"],correct:1,explain:"% concentration = (grams ÷ mL) × 100 = (5 ÷ 200) × 100 = 0.025 × 100 = 2.5%. This is read as 2.5% w/v (weight/volume) concentration."},
    {q:"A patient's urine output over 8 hours is 320 mL. Is this within normal range?",opts:["No, too low (below 240mL minimum)","Yes, normal (240-480mL expected)","No, too high","Cannot determine without weight"],correct:1,explain:"Normal minimum urine output = 30 mL/hr. Over 8 hours: 30 × 8 = 240 mL minimum. 320 mL ÷ 8 hrs = 40 mL/hr, which is within normal range (30-60 mL/hr is typical)."},
    {q:"Using C1V1 = C2V2, how many mL of a 70% solution is needed to make 500 mL of a 35% solution?",opts:["175 mL","250 mL","350 mL","500 mL"],correct:1,explain:"C1V1 = C2V2 → 70 × V1 = 35 × 500 → V1 = 17,500 ÷ 70 = 250 mL. Add water to make total volume 500 mL. Used in lab and pharmacy dilution calculations."},
    {q:"A clinical study reports sensitivity of 95% and specificity of 80% for a diagnostic test. What does 80% specificity mean?",opts:["80% of sick patients test positive","80% of healthy patients correctly test negative","80% accuracy overall","80% chance the positive result is correct"],correct:1,explain:"Specificity = true negative rate. 80% specificity means the test correctly identifies 80% of healthy people as disease-free. The other 20% are false positives. High specificity is needed for confirmatory tests."},
    {q:"What is 2.5 grams converted to micrograms?",opts:["2,500 mcg","25,000 mcg","250,000 mcg","2,500,000 mcg"],correct:3,explain:"1 gram = 1,000 mg = 1,000,000 mcg. So 2.5 g = 2.5 × 1,000,000 = 2,500,000 mcg. Always use dimensional analysis: 2.5g × (1000mg/1g) × (1000mcg/1mg) = 2,500,000 mcg."},
    {q:"A patient's blood glucose readings over a week are: 95, 102, 98, 115, 89, 107, 110. What is the mean?",opts:["98 mg/dL","102.3 mg/dL","107 mg/dL","110 mg/dL"],correct:1,explain:"Mean = sum ÷ count = (95+102+98+115+89+107+110) ÷ 7 = 716 ÷ 7 = 102.3 mg/dL. The mean blood glucose helps assess overall glycemic control."},
    {q:"A drug label reads 250 mg/5 mL. A patient needs 375 mg. How many mL should be given?",opts:["5 mL","7.5 mL","10 mL","15 mL"],correct:1,explain:"Dosage formula: (desired ÷ on hand) × quantity = (375 ÷ 250) × 5 mL = 1.5 × 5 = 7.5 mL. Always double-check by unit analysis: 7.5 mL × 250mg/5mL = 375 mg ✓"},
    {q:"A research study shows a treatment reduces infection rate from 8% to 4%. What is the relative risk reduction?",opts:["4%","50%","200%","400%"],correct:1,explain:"Relative risk reduction = absolute reduction ÷ control rate = 4% ÷ 8% = 0.5 = 50%. Absolute risk reduction = 4%. Relative risk reduction (50%) sounds more impressive — always check both when evaluating research."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"A patient needs 1.5 g of a drug. Available: 500 mg tablets. How many tablets are needed?",opts:["1.5 tablets","2 tablets","3 tablets","4 tablets"],correct:2,explain:"Convert: 1.5g = 1500mg. Tablets needed = 1500mg ÷ 500mg/tablet = 3 tablets. Always convert to same units first, then apply dosage formula."},
    {q:"Drug A has a half-life of 12 hours and is given at 0600. After how many hours will 87.5% of the drug be eliminated?",opts:["12 hours","24 hours","36 hours","48 hours"],correct:2,explain:"After 1 half-life: 50% eliminated, 50% remains. After 2 half-lives: 75% eliminated, 25% remains. After 3 half-lives: 87.5% eliminated, 12.5% remains. 3 × 12hr = 36 hours."},
    {q:"A 95% confidence interval for a drug's blood pressure reduction is -8 to -2 mmHg. What can you conclude?",opts:["The drug has no effect","The drug significantly reduces BP (CI does not include 0)","More studies are needed before any conclusion","The drug raises BP in 5% of patients"],correct:1,explain:"A 95% CI that does NOT include zero indicates a statistically significant result. The entire CI (-8 to -2) is on the negative side, meaning the drug consistently reduces BP. If the CI included 0, the result would not be statistically significant."},
    {q:"A nurse must infuse 1000 mL of NS at 125 mL/hr using a pump. The infusion started at 0900. When will it finish?",opts:["1700","1800","1900","2000"],correct:0,explain:"1000 mL ÷ 125 mL/hr = 8 hours. 0900 + 8 hours = 1700 (5:00 PM). Time-to-completion calculations are essential for planning nursing care and scheduling next bag changes."},
  ]);
})();

// ══════════════════════════════════════════════════════════════════════════
// HEALTH CAREERS EXPANSION
// ══════════════════════════════════════════════════════════════════════════
(function expandCareers(){
  if(!window.QB_CAREERS) return;
  var fc = window.QB_CAREERS.flashcards;
  var qz = window.QB_CAREERS.quiz;

  fc.easy = fc.easy.concat([
    {term:"Primary care physician",def:"First-contact doctor for routine and preventive care — refers to specialists",breakdown:"Family medicine, internal medicine, pediatrics, OB/GYN are primary care fields. The 'medical home' for patients"},
    {term:"Specialist",def:"Physician with advanced training in a specific body system or disease type",breakdown:"Cardiologist (heart), neurologist (nervous system), orthopedist (bones), dermatologist (skin). Seen after PCP referral"},
    {term:"Registered Nurse (RN)",def:"Licensed healthcare professional who provides patient care, administers medications, coordinates with physicians",breakdown:"Requires BSN or associate degree + NCLEX-RN exam. Most common healthcare professional. Works in hospitals, clinics, homes"},
    {term:"Licensed Practical Nurse (LPN)",def:"Healthcare professional who provides basic nursing care under RN or physician supervision",breakdown:"Also called LVN (Licensed Vocational Nurse) in some states. Shorter training than RN. Works in nursing homes, clinics"},
    {term:"Nurse Practitioner (NP)",def:"Advanced practice RN who can diagnose, treat, and prescribe — can practice independently in many states",breakdown:"Master's or doctoral level. Specialties parallel physician specialties: FNP, PNP, ACNP. Growing role in primary care shortage"},
    {term:"Physician Assistant (PA)",def:"Medical professional licensed to practice medicine with physician supervision — diagnoses, treats, prescribes",breakdown:"Master's level training. Works in all medical and surgical specialties. More flexible than physicians for many healthcare settings"},
    {term:"Pharmacist (PharmD)",def:"Drug therapy expert — dispenses medications, counsels patients, checks drug interactions, manages therapy",breakdown:"Doctor of Pharmacy degree (6 years). Clinical pharmacists on hospital teams help optimize medication regimens and prevent errors"},
    {term:"Physical Therapist (PT)",def:"Rehabilitates patients with physical impairments — improves mobility, strength, function after injury or illness",breakdown:"Doctoral degree (DPT). Works with orthopedic, neurological, cardiac, and pediatric patients. Prescribes therapeutic exercise"},
    {term:"Occupational Therapist (OT)",def:"Helps patients perform daily activities (occupations) after illness, injury, or disability",breakdown:"Master's degree. Focuses on functional independence: dressing, cooking, work tasks. Works with stroke, hand injury, autism"},
    {term:"Respiratory Therapist (RT)",def:"Manages breathing disorders — operates ventilators, administers breathing treatments, performs pulmonary function tests",breakdown:"Associate or bachelor's degree. Works in ICU, ER, NICU. Manages patients on mechanical ventilation. Critical in COVID response"},
    {term:"Radiologic Technologist",def:"Takes X-rays, CT scans, MRI images — operates diagnostic imaging equipment",breakdown:"Associate or bachelor's degree. Specializations: CT technologist, MRI technologist, mammographer, interventional radiology"},
    {term:"Surgical Technologist",def:"Sets up operating room, prepares sterile field, assists surgeon during procedures",breakdown:"Certificate or associate degree. Part of the surgical team alongside surgeon and circulating nurse. Maintains sterile technique"},
    {term:"Medical Assistant (MA)",def:"Clinical and administrative support in physician offices — takes vitals, assists with exams, handles scheduling",breakdown:"Certificate or associate degree. Growing field. Front-line patient interaction in outpatient settings. Not the same as CNA"},
    {term:"Certified Nursing Assistant (CNA)",def:"Provides basic patient care — bathing, feeding, vital signs, repositioning — under nurse supervision",breakdown:"State-approved training program (4-12 weeks). Entry-level healthcare. Common pathway to nursing. Long-term care and hospitals"},
    {term:"Emergency Medical Technician (EMT)",def:"Provides emergency medical care in the field and transport to hospital",breakdown:"EMT-Basic: airway, bleeding, fractures, CPR, basic medications. Paramedic: advanced level — IVs, medications, intubation, advanced procedures"},
    {term:"Paramedic",def:"Advanced EMT who can perform complex interventions — IVs, medications, intubation, cardiac monitoring",breakdown:"1,200+ hours training beyond EMT. Works in ambulance, helicopter EMS. Can administer 30+ medications and perform advanced procedures"},
    {term:"Medical Laboratory Scientist (MLS)",def:"Analyzes blood, tissue, body fluids for disease diagnosis — runs laboratory tests",breakdown:"Bachelor's degree. Also called clinical laboratory scientist (CLS). Performs CBC, cultures, coagulation tests, blood typing"},
    {term:"Phlebotomist",def:"Draws blood samples from patients for laboratory testing",breakdown:"Certificate program (few weeks to months). High-demand entry-level position. Works in hospitals, clinics, blood banks"},
    {term:"Dentist (DDS/DMD)",def:"Diagnoses and treats diseases of teeth, gums, and oral structures",breakdown:"4-year dental school after bachelor's degree. General dentists do cleanings, fillings, extractions. Specialists: orthodontist, periodontist, oral surgeon"},
    {term:"Dental Hygienist",def:"Licensed professional who cleans teeth, takes X-rays, educates patients on oral health",breakdown:"Associate or bachelor's degree. Works under dentist supervision. Examines for oral diseases, documents findings, provides preventive care"},
    {term:"Optometrist (OD)",def:"Examines eyes, diagnoses vision problems, prescribes corrective lenses and some medications",breakdown:"4-year optometry school. Does NOT perform surgery (that's ophthalmologist, an MD). Manages glaucoma, diabetic eye disease"},
    {term:"Podiatrist (DPM)",def:"Diagnoses and treats conditions of the foot, ankle, and lower leg",breakdown:"4-year podiatric medical school. Performs foot surgery. Manages diabetic foot complications — a leading cause of amputation"},
    {term:"Dietitian/Nutritionist (RD/RDN)",def:"Assesses nutritional needs, creates medical nutrition therapy plans, counsels on diet",breakdown:"Bachelor's degree + supervised internship + RD exam. Works in hospitals, schools, public health. Medical nutrition therapy for diabetes, kidney disease, eating disorders"},
    {term:"Social Worker (MSW/LCSW)",def:"Addresses social, psychological, and economic factors affecting health — connects patients to resources",breakdown:"Master's degree. In hospitals: discharge planning, insurance navigation, mental health support, abuse reporting"},
    {term:"Health Information Manager",def:"Manages patient medical records, coding, data integrity, privacy (HIPAA) compliance",breakdown:"Bachelor's degree. RHIA certification. ICD-10 coding for billing. Ensures accurate, secure medical records. Growing field with EHR systems"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"Scope of practice",def:"Legal boundaries defining what a healthcare professional is allowed to do based on their training and license",breakdown:"Varies by state. RN can administer medications; CNA cannot. NP scope varies: independent practice in some states, supervised in others"},
    {term:"Interdisciplinary team",def:"Healthcare team from different professions collaborating for patient care",breakdown:"Hospital team: physician, NP/PA, RN, pharmacist, PT/OT, social worker, dietitian. Better outcomes than siloed individual care"},
    {term:"Continuing education (CE)",def:"Required education to maintain professional licensure — healthcare fields require regular updates",breakdown:"Nurses: 20-30 CE hours per 2-year license renewal. Physicians: 50 CME hours/year. Ensures providers stay current with evidence"},
    {term:"National Provider Identifier (NPI)",def:"Unique 10-digit number identifying healthcare providers for billing and administration",breakdown:"Required for all healthcare providers who bill insurance. Used in HIPAA transactions. Covered entities must use NPI in claims"},
    {term:"Credentials and credentialing",def:"Process of verifying a provider's qualifications before granting hospital privileges",breakdown:"Hospital checks: medical school, residency, board certification, malpractice history, references. Must be renewed every 2 years"},
    {term:"Health Maintenance Organization (HMO)",def:"Insurance plan requiring primary care physician referrals to see specialists — lower cost, less flexibility",breakdown:"Patient selects a PCP who coordinates care. Must use in-network providers or pay full cost. Lower premiums than PPO"},
    {term:"Preferred Provider Organization (PPO)",def:"Insurance plan allowing patients to see any provider — higher cost, more flexibility",breakdown:"Can see specialists without referral. Out-of-network coverage (at higher cost). More expensive premiums than HMO"},
    {term:"Fee-for-service",def:"Payment model where providers are paid for each service performed — incentivizes volume over value",breakdown:"Traditional model. Criticized for incentivizing unnecessary procedures. Being replaced by value-based care models"},
    {term:"Value-based care",def:"Payment model linking provider reimbursement to patient outcomes and quality rather than volume",breakdown:"Accountable Care Organizations (ACOs), bundled payments, pay-for-performance. Goal: better outcomes at lower cost"},
    {term:"Electronic Health Record (EHR)",def:"Digital version of patient medical records shared across providers and healthcare systems",breakdown:"Replaced paper charts. HITECH Act (2009) incentivized adoption. Improves care coordination, reduces errors, enables data analysis"},
    {term:"HIPAA Privacy Rule",def:"Federal regulation protecting patient health information — who can see it and how it can be shared",breakdown:"Patients have right to access their records. Providers can share for treatment, payment, operations. Violations: fines up to $1.9M/year"},
    {term:"Informed consent",def:"Patient's right to understand and agree to treatment before it is performed",breakdown:"Must include: what procedure is, why needed, risks, benefits, alternatives, right to refuse. Patient must be competent to consent. Written for surgery"},
    {term:"Advance directive",def:"Legal document stating a patient's wishes for medical treatment if they cannot speak for themselves",breakdown:"Living will: specific treatment preferences. Healthcare proxy/POA: designates decision-maker. DNR: do not resuscitate order"},
    {term:"Medical malpractice",def:"Professional negligence by a healthcare provider that causes patient harm",breakdown:"Four elements: duty, breach, causation, damages. Requires expert testimony. Malpractice insurance required for most providers"},
    {term:"Burnout in healthcare",def:"Chronic occupational stress causing exhaustion, cynicism, and reduced professional efficacy",breakdown:"Affects 50%+ of physicians, 35%+ of nurses. Leads to medical errors, turnover, substance abuse. COVID significantly worsened rates"},
    {term:"Cultural competence",def:"Ability to effectively serve patients from diverse cultural backgrounds — respecting values and beliefs",breakdown:"Essential skill: over 400 languages spoken in U.S. healthcare. Includes: health literacy, interpreter services, avoiding assumptions"},
    {term:"Telehealth",def:"Healthcare services delivered remotely via technology — video, phone, remote monitoring",breakdown:"Expanded dramatically during COVID. Improves access for rural patients. Reimbursement rules still evolving. Not appropriate for all conditions"},
    {term:"Health literacy",def:"Patient's ability to understand and use health information to make informed decisions",breakdown:"Only 12% of U.S. adults have proficient health literacy. Poor health literacy linked to worse outcomes. Providers must use plain language"},
    {term:"Case management",def:"Coordinating care across providers and settings for patients with complex needs",breakdown:"Case managers are RNs or social workers. Ensure appropriate care transitions, prevent readmissions, coordinate resources"},
    {term:"Discharge planning",def:"Preparing patient for safe transition from hospital to next care setting",breakdown:"Begins at admission. Includes: home care needs, medication reconciliation, follow-up appointments, patient/family education"},
  ]);

  fc.hard = fc.hard.concat([
    {term:"Triple aim (IHI)",def:"Institute for Healthcare Improvement's framework: better patient experience, better population health, lower per capita cost",breakdown:"Proposed by Don Berwick in 2008. Now 'Quadruple Aim' adds: improving provider experience (reducing burnout)"},
    {term:"Population health management",def:"Managing the health outcomes of a group of individuals — preventive, not just acute care",breakdown:"Uses data analytics to identify at-risk populations. Social determinants of health (SDOH) addressed. ACOs use population health approach"},
    {term:"Social determinants of health (SDOH)",def:"Non-medical factors influencing health: housing, food, education, income, social support",breakdown:"Account for 30-55% of health outcomes. Poverty, food insecurity, unsafe housing have larger health impact than clinical care alone"},
    {term:"Accountable Care Organization (ACO)",def:"Group of providers sharing responsibility for quality and cost of care for a defined population",breakdown:"CMS Medicare Shared Savings Program. ACOs rewarded for keeping patients healthy and avoiding unnecessary hospitalizations"},
    {term:"Magnet Recognition Program",def:"ANCC designation for hospitals demonstrating nursing excellence and superior patient outcomes",breakdown:"Magnet hospitals have better nurse retention, lower mortality, higher patient satisfaction. Requires shared governance, evidence-based practice"},
    {term:"Nurse-to-patient ratio",def:"Number of patients assigned to each nurse — affects safety and outcomes",breakdown:"California only U.S. state mandating ratios (1:5 med-surg, 1:2 ICU). Studies show each additional patient per RN increases 30-day mortality 7%"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"Which healthcare professional is typically the first point of contact for routine medical care?",opts:["Specialist physician","Emergency physician","Primary care physician","Surgeon"],correct:2,explain:"Primary care physicians (family medicine, internal medicine, pediatrics) are the first point of contact for routine and preventive care. They diagnose common conditions and refer patients to specialists when needed."},
    {q:"What does 'scope of practice' define in healthcare?",opts:["A provider's salary range","The geographic area where a provider can work","The legal boundaries of what a provider is allowed to do based on their training and license","The number of patients a provider can see per day"],correct:2,explain:"Scope of practice defines the legal boundaries of what a healthcare professional can do based on their education, training, and license. It varies by profession and state. For example, CNAs can take vital signs but cannot administer medications."},
    {q:"Which healthcare role focuses on helping patients perform daily activities after illness or injury?",opts:["Physical Therapist","Occupational Therapist","Respiratory Therapist","Speech-Language Pathologist"],correct:1,explain:"Occupational Therapists (OT) help patients regain ability to perform daily activities (occupations) like dressing, cooking, and working. PTs focus on movement and strength. RTs focus on breathing. SLPs focus on speech and swallowing."},
    {q:"HIPAA primarily protects which type of patient information?",opts:["Financial records","Protected Health Information (PHI)","Employment records","Credit history"],correct:1,explain:"HIPAA (Health Insurance Portability and Accountability Act) protects Protected Health Information (PHI) — any information that can identify a patient and relates to their health condition, treatment, or payment. This includes medical records, test results, and billing information."},
    {q:"What is the primary difference between an RN and an LPN/LVN?",opts:["RNs work in hospitals; LPNs work in nursing homes only","RNs have more education and a broader scope of practice than LPNs","LPNs can prescribe medications; RNs cannot","They have exactly the same role with different titles"],correct:1,explain:"RNs (Registered Nurses) have more education (associate or bachelor's degree + NCLEX-RN) and a broader scope of practice than LPNs/LVNs (Licensed Practical/Vocational Nurses). LPNs provide basic nursing care under RN or physician supervision."},
    {q:"Which healthcare professional specializes in analyzing blood and body fluid samples?",opts:["Phlebotomist","Medical Laboratory Scientist","Radiologic Technologist","Surgical Technologist"],correct:1,explain:"Medical Laboratory Scientists (MLS) analyze blood, tissue, and body fluid samples to diagnose disease. They run tests like CBCs, cultures, and blood typing. Phlebotomists draw the blood; MLS analyze it."},
    {q:"What is informed consent?",opts:["A patient's permission for a provider to bill insurance","Patient's right to understand and agree to treatment before it is performed","Written permission from family members for surgery","Insurance approval for a medical procedure"],correct:1,explain:"Informed consent is the patient's right to understand a procedure's purpose, risks, benefits, and alternatives before agreeing to it. Patients must be competent to consent. For surgery, written consent is required. Patients always have the right to refuse."},
    {q:"An advance directive primarily addresses which situation?",opts:["What to do if a patient cannot pay for care","Patient's treatment wishes if they become unable to communicate","How to handle a medical malpractice claim","Employment benefits for healthcare workers"],correct:1,explain:"An advance directive states a patient's wishes for medical treatment if they cannot speak for themselves (unconscious, severe dementia, etc.). Includes living wills (specific treatment preferences) and healthcare proxies (designating a decision-maker)."},
    {q:"What degree does a Nurse Practitioner (NP) require?",opts:["Associate degree","Bachelor's degree","Master's or doctoral degree","Medical Doctor (MD) degree"],correct:2,explain:"Nurse Practitioners require master's or doctoral-level education beyond their RN license. They can diagnose, treat, and prescribe medications. In many states, NPs can practice independently without physician supervision."},
    {q:"What is the primary role of a Respiratory Therapist?",opts:["Administer physical rehabilitation exercises","Manage breathing disorders and ventilator support","Perform surgical procedures","Analyze laboratory specimens"],correct:1,explain:"Respiratory Therapists (RTs) manage breathing disorders — they operate mechanical ventilators, administer breathing treatments (nebulizers), perform pulmonary function tests, and assist with intubation. Critical in ICUs and with patients who have lung conditions."},
    {q:"Which insurance model requires a PCP referral to see a specialist?",opts:["PPO (Preferred Provider Organization)","HMO (Health Maintenance Organization)","Medicare","Medicaid"],correct:1,explain:"HMOs (Health Maintenance Organizations) require patients to select a primary care physician who coordinates all care and provides referrals to specialists. HMOs are generally less expensive but offer less flexibility than PPOs."},
    {q:"What does EHR stand for in healthcare?",opts:["Emergency Health Response","Electronic Health Record","Essential Health Requirement","Extended Hospital Record"],correct:1,explain:"EHR stands for Electronic Health Record — the digital version of a patient's medical records shared across providers and healthcare systems. EHRs replaced paper charts and enable care coordination, reduce errors, and allow data analysis."},
    {q:"Which health professional has a Doctorate of Pharmacy (PharmD) degree?",opts:["Physician","Pharmacist","Physical Therapist","Podiatrist"],correct:1,explain:"Pharmacists earn a Doctorate of Pharmacy (PharmD) — a 4-year professional degree. They dispense medications, counsel patients, check for drug interactions, and manage medication therapy. Clinical pharmacists are essential members of hospital care teams."},
    {q:"What is burnout in the healthcare context?",opts:["Physical exhaustion from long shifts","Chronic occupational stress causing exhaustion, cynicism, and reduced professional efficacy","A term for hospital budget deficits","Equipment failure from overuse"],correct:1,explain:"Healthcare burnout is a syndrome of chronic occupational stress resulting in emotional exhaustion, depersonalization (cynicism), and reduced sense of personal accomplishment. It affects 50%+ of physicians and 35%+ of nurses, contributing to medical errors and turnover."},
    {q:"What is the role of a case manager in healthcare?",opts:["Managing hospital finances","Coordinating care across providers and settings for complex patients","Performing surgical case setups","Managing medical staff scheduling"],correct:1,explain:"Case managers (usually RNs or social workers) coordinate care for patients with complex needs across providers and settings — ensuring smooth transitions, preventing readmissions, connecting patients with community resources, and managing insurance authorizations."},
    {q:"Cultural competence in healthcare primarily means:",opts:["Speaking multiple languages fluently","Effectively serving patients from diverse cultural backgrounds by respecting their values and beliefs","Only treating patients from the same culture as the provider","Requiring patients to adopt mainstream healthcare values"],correct:1,explain:"Cultural competence means the ability to effectively serve patients from diverse cultural backgrounds, respecting their values, beliefs, and communication styles. This includes using interpreter services, understanding cultural health practices, and avoiding stereotypical assumptions."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"A patient refuses a recommended blood transfusion due to religious beliefs. What is the appropriate response?",opts:["Administer the transfusion anyway — the patient's life is at risk","Respect the patient's right to refuse — document the refusal and explore alternatives","Contact a judge to override the decision","Discharge the patient immediately"],correct:1,explain:"Competent adults have the absolute right to refuse medical treatment, even life-saving treatment. The provider must document the refusal, ensure the patient understands the risks, and explore acceptable alternatives. This is a fundamental principle of patient autonomy and informed consent."},
    {q:"What is the Triple Aim framework developed by the Institute for Healthcare Improvement?",opts:["Safety, Quality, Efficiency","Better patient experience, better population health, lower per capita cost","Access, Quality, Affordability","Prevention, Treatment, Recovery"],correct:1,explain:"The Triple Aim (IHI, 2008) has three interdependent goals: (1) improve patient experience of care, (2) improve population health, (3) reduce per capita healthcare costs. Often expanded to 'Quadruple Aim' by adding improving provider experience."},
    {q:"Which factor is considered a Social Determinant of Health (SDOH)?",opts:["A patient's genetic predisposition to cancer","Access to nutritious food and safe housing","A patient's cholesterol level","The effectiveness of a prescribed medication"],correct:1,explain:"Social Determinants of Health are non-medical factors that influence health outcomes: food security, housing stability, education, income, social support, transportation, and neighborhood safety. SDOH account for an estimated 30-55% of health outcomes."},
    {q:"A Physician Assistant differs from a Nurse Practitioner primarily in that:",opts:["PAs can prescribe controlled substances; NPs cannot","PAs come from a medical model education; NPs from a nursing model","NPs require physician supervision in all states; PAs do not","PAs hold doctoral degrees; NPs hold master's degrees"],correct:1,explain:"PAs are trained in the medical model (similar to physicians, disease-focused). NPs come from nursing education and a nursing model emphasizing holistic care. Both can diagnose, treat, and prescribe; however, their educational frameworks and philosophies differ."},
    {q:"What does 'value-based care' mean in contrast to 'fee-for-service'?",opts:["Patients pay based on how much they value the care received","Providers are paid based on patient outcomes and quality rather than volume of services","Care is provided at a discount for uninsured patients","Services are billed based on their market value"],correct:1,explain:"Value-based care links provider payment to patient outcomes, quality metrics, and efficiency rather than volume. Fee-for-service pays for each service regardless of outcome. Value-based models (ACOs, bundled payments) incentivize keeping patients healthy and avoiding unnecessary procedures."},
    {q:"A hospital is seeking Magnet Recognition. What does this designation indicate?",opts:["The hospital uses magnetic resonance imaging","The hospital has demonstrated nursing excellence and superior patient outcomes","The hospital attracts the most patients in the region","The hospital has the strongest financial performance"],correct:1,explain:"Magnet Recognition (from ANCC) is the gold standard for nursing excellence. Magnet hospitals demonstrate strong nursing leadership, shared governance, evidence-based practice, and consistently better patient outcomes including lower mortality and higher patient satisfaction."},
    {q:"Telehealth expanded significantly during COVID-19. What is a major ongoing limitation?",opts:["Telehealth can only treat infectious diseases","Not all conditions are appropriate for remote care and reimbursement rules are still evolving","Telehealth requires patients to come to a clinic","Telehealth is only available to patients with smartphones"],correct:1,explain:"While telehealth dramatically improves access — especially for rural patients — limitations include: not all conditions can be safely managed remotely (requires physical exam), reimbursement policies vary by payer and state, technology barriers exist for elderly or low-income patients, and licensure across state lines is complex."},
    {q:"What is health literacy and why does it matter clinically?",opts:["A measure of how much a provider knows about health","A patient's ability to understand and use health information to make decisions — poor health literacy leads to worse outcomes","The amount of health education a patient has completed","A provider's ability to explain diagnoses clearly"],correct:1,explain:"Health literacy is a patient's ability to obtain, process, and understand health information needed to make appropriate decisions. Only 12% of U.S. adults have proficient health literacy. Poor health literacy is linked to worse chronic disease management, more hospitalizations, and lower medication adherence."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"A state law gives NPs full practice authority. What does this mean clinically?",opts:["NPs can perform surgery independently","NPs can diagnose, treat, and prescribe without physician oversight in that state","NPs earn the same salary as physicians","NPs must consult physicians for all complex cases"],correct:1,explain:"Full practice authority (granted by 26+ states) allows NPs to evaluate patients, diagnose conditions, interpret tests, initiate treatment plans, and prescribe medications without a physician collaboration agreement. Reduces barriers in areas with physician shortages."},
    {q:"A hospital implements a 1:4 nurse-to-patient ratio. Based on research, what outcome would you predict?",opts:["No change — ratios don't affect outcomes","Increased costs with no quality improvement","Reduced patient mortality and improved nurse retention","Increased nurse burnout from higher expectations"],correct:2,explain:"Research consistently shows lower nurse-to-patient ratios improve outcomes. Aiken et al. found each additional patient per nurse is associated with 7% increased 30-day mortality and 23% higher nurse burnout odds. California mandated ratios reduced mortality and improved nurse retention."},
    {q:"What is an Accountable Care Organization (ACO) and how does it differ from a traditional hospital?",opts:["An ACO is a specialty hospital for complex care","An ACO is a group of providers sharing responsibility for quality and cost of care for a defined population, rewarded for keeping patients healthy","An ACO is a government agency overseeing hospital compliance","An ACO is an insurance company that owns hospitals"],correct:1,explain:"ACOs are networks of doctors, hospitals, and other providers who voluntarily coordinate care for Medicare patients. If they provide high-quality care while spending less than projected, they share in the savings. This incentivizes prevention and care coordination rather than volume."},
  ]);
})();

// ══════════════════════════════════════════════════════════════════════════
// LIFE THREATENING SITUATIONS (EMERGENCY) EXPANSION
// ══════════════════════════════════════════════════════════════════════════
(function expandEmergency(){
  if(!window.QB_EMERGENCY) return;
  var fc = window.QB_EMERGENCY.flashcards;
  var qz = window.QB_EMERGENCY.quiz;

  fc.easy = fc.easy.concat([
    {term:"Chain of Survival (AHA)",def:"5 links: Recognition → Activation → CPR → Defibrillation → Advanced Care → Recovery",breakdown:"Each link must be strong. Early CPR doubles survival. AED within 3-5 min = 50-70% survival. Delay drops survival 10% per minute"},
    {term:"Good Samaritan Law",def:"Legal protection for bystanders who provide emergency care in good faith",breakdown:"Protects from liability when acting reasonably and in good faith. Encourages bystander response. Varies by state but exists in all 50 states"},
    {term:"Standard of care",def:"What a reasonably trained person would do in the same situation — the legal benchmark",breakdown:"EMT standard of care = what a competent EMT would do. Deviation from standard of care = negligence. Critical for liability"},
    {term:"Consent (emergency)",def:"Expressed: patient agrees verbally/in writing. Implied: assumed when unconscious and life-threatening",breakdown:"Implied consent allows treatment of unresponsive adults. Minors: parent/guardian consent needed unless life-threatening emergency"},
    {term:"Primary assessment (ABCs)",def:"Airway, Breathing, Circulation — first priorities in any emergency",breakdown:"Check in order: is airway open? Are they breathing? Is heart beating/blood circulating? Life threats addressed before history-taking"},
    {term:"Secondary assessment",def:"Head-to-toe examination after life threats addressed — gather history, vital signs, physical exam",breakdown:"SAMPLE history: Signs/symptoms, Allergies, Medications, Past history, Last meal, Events. Done after ABCs stable"},
    {term:"SAMPLE history",def:"Signs/symptoms, Allergies, Medications, Past medical history, Last oral intake, Events leading up",breakdown:"Standardized medical history framework. Used by EMTs, nurses, physicians. Quick way to gather essential patient information"},
    {term:"Anaphylaxis signs",def:"Hives, throat swelling, difficulty breathing, drop in blood pressure, rapid heart rate, nausea",breakdown:"Systemic allergic reaction — can be fatal within minutes. Trigger: food, medication, insect venom, latex. Epinephrine is first-line treatment"},
    {term:"Epinephrine (EpiPen)",def:"First-line treatment for anaphylaxis — counteracts allergic response, opens airways, raises BP",breakdown:"Auto-injector given in outer thigh, through clothing. Works within minutes. Second EpiPen if no improvement in 5-15 min. Call 911 always"},
    {term:"Stroke signs (BE-FAST)",def:"Balance, Eyes, Face drooping, Arm weakness, Speech difficulty, Time to call 911",breakdown:"Every minute in stroke: 1.9 million neurons die. 'Time is brain.' Get to stroke center within 3-4.5 hours for clot-busting tPA treatment"},
    {term:"Heart attack symptoms",def:"Chest pain/pressure, left arm/jaw pain, shortness of breath, sweating, nausea, lightheadedness",breakdown:"Women often have atypical symptoms: jaw pain, fatigue, nausea. Silent MI (no chest pain) in diabetics and elderly. Call 911, chew aspirin"},
    {term:"Shock",def:"Life-threatening state of inadequate tissue perfusion — cells not getting enough oxygen",breakdown:"Types: hypovolemic (blood loss), cardiogenic (pump failure), distributive (septic, anaphylactic, neurogenic), obstructive. Signs: pale, cool, rapid weak pulse"},
    {term:"Hypovolemic shock",def:"Shock from blood or fluid loss — most common type in trauma",breakdown:"Class I: <15% loss. Class II: 15-30% (tachycardia). Class III: 30-40% (confusion). Class IV: >40% (life-threatening). Treat with IV fluids, blood products"},
    {term:"Recovery position",def:"Side-lying position for unconscious breathing patient — prevents aspiration",breakdown:"Roll patient onto side, bend top knee forward, tilt head back slightly to maintain airway. Gravity prevents vomit aspiration. Check breathing continuously"},
    {term:"Spinal precautions",def:"Protecting the spine from movement after potential spinal injury — minimize movement",breakdown:"Mechanism: MVA, fall from height, diving injury, direct spine trauma. Assess: pain, tenderness, neuro deficits. Cervical collar + backboard if concerned"},
    {term:"Drowning response",def:"Remove from water safely → assess → begin CPR if not breathing → AED if available → call 911",breakdown:"Do NOT attempt rescue if untrained — two deaths become likely. Throw rope/flotation device first. Cold water may protect brain longer"},
    {term:"Hypoglycemia",def:"Blood glucose <70 mg/dL — causes confusion, shakiness, sweating, seizures, unconsciousness",breakdown:"Treatment: conscious patient → 15g fast-acting carbs (juice, glucose tablets). Unconscious → glucagon injection or IV glucose. Check glucose again in 15 min"},
    {term:"Hyperglycemia",def:"Blood glucose >180 mg/dL — causes increased thirst/urination, blurred vision, fatigue",breakdown:"Diabetic ketoacidosis (DKA) if severe. Treatment: insulin, IV fluids, electrolyte correction. Emergency if >600 mg/dL (hyperosmolar crisis)"},
    {term:"Seizure first aid",def:"Keep safe, do NOT restrain, turn on side if possible, time the seizure, call 911 if >5 minutes",breakdown:"DO NOT put anything in mouth. Protect head. Most end in 1-3 minutes. Status epilepticus: seizure >5 min = emergency. Post-ictal period normal"},
    {term:"Burns classification",def:"First degree: epidermis only. Second degree: epidermis + dermis. Third degree: full thickness including deep tissue",breakdown:"First: redness (sunburn). Second: blisters. Third: white/brown/charred, painless (nerve damage). Treat: cool water, cover, no ice, no butter"},
    {term:"Rule of Nines (burn area)",def:"Body surface area: head 9%, each arm 9%, chest 18%, back 18%, each leg 18%, genitals 1%",breakdown:"Used to estimate burn extent for fluid resuscitation calculation. Burns >20% BSA require IV fluids. Children use Lund-Browder chart (proportions differ)"},
    {term:"Tourniquet application",def:"Tight band applied 2-3 inches above wound to stop life-threatening extremity bleeding",breakdown:"Apply high and tight. Tighten until bleeding stops. Note time applied. Do not remove once applied. Acceptable in life-threatening bleeding — loss of limb vs loss of life"},
    {term:"Obstructed airway (conscious adult)",def:"Severe obstruction: cannot speak, cough, or breathe — give 5 back blows then 5 abdominal thrusts (Heimlich)",breakdown:"Mild obstruction: encourage coughing. Severe: five back blows between shoulder blades, then five abdominal thrusts. Repeat until dislodged or unconscious"},
    {term:"Triage",def:"Sorting patients by severity when resources are limited — prioritize who can benefit most from immediate care",breakdown:"START triage: Simple Triage And Rapid Treatment. Colors: Black (deceased/unsalvageable), Red (immediate), Yellow (delayed), Green (minor/walking wounded)"},
    {term:"Heat stroke",def:"Core temperature >104°F with neurological symptoms (confusion, slurred speech) — life-threatening emergency",breakdown:"Heat exhaustion precedes heat stroke: heavy sweating, nausea, cool skin. Heat stroke: hot dry skin, confusion. Rapid cooling is life-saving treatment"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"Ventricular fibrillation (VF)",def:"Chaotic, disorganized heart electrical activity — heart quivers, no effective pumping — cardiac arrest",breakdown:"Most common initial rhythm in sudden cardiac arrest. Only effective treatment: defibrillation (within 3-5 min ideally) + CPR. AED can detect and shock VF"},
    {term:"Ventricular tachycardia (VT)",def:"Fast, abnormal heart rhythm originating in ventricles — may or may not have a pulse",breakdown:"Pulseless VT: treat same as VF (CPR + defibrillation). VT with pulse: may convert with medication or synchronized cardioversion"},
    {term:"Pulseless electrical activity (PEA)",def:"Organized electrical activity on monitor but no pulse — requires CPR and identifying reversible cause",breakdown:"Not shockable. H's: Hypovolemia, Hypoxia, Hydrogen ion (acidosis), Hypo/Hyperkalemia, Hypothermia. T's: Tension pneumothorax, Tamponade, Toxins, Thrombosis"},
    {term:"Asystole",def:"Absence of cardiac electrical activity — 'flatline' — not shockable, requires CPR + reversible cause treatment",breakdown:"Worst prognosis of all arrest rhythms. Confirm in two leads. CPR + epinephrine + identify cause. Survival rare but possible with rapid cause correction"},
    {term:"Tension pneumothorax",def:"Air trapped in pleural space under pressure — collapses lung, shifts mediastinum, compresses heart",breakdown:"Causes: chest trauma, mechanical ventilation. Signs: absent breath sounds, tracheal deviation, JVD, hypotension. Treatment: needle decompression (2nd ICS, MCL)"},
    {term:"Cardiac tamponade",def:"Fluid in pericardial sac compresses heart — impairs filling and output",breakdown:"Beck's Triad: hypotension, muffled heart sounds, JVD. Causes: trauma, malignancy, pericarditis. Treatment: pericardiocentesis (needle drainage)"},
    {term:"Traumatic brain injury (TBI)",def:"Brain injury from external force — ranges from mild concussion to severe diffuse axonal injury",breakdown:"Signs of increased ICP: Cushing's triad (hypertension, bradycardia, irregular breathing). Avoid hypoxia and hypotension — each worsens outcomes significantly"},
    {term:"Glasgow Coma Scale (GCS)",def:"Neurological assessment: Eye opening (1-4) + Verbal response (1-5) + Motor response (1-6) = 3-15",breakdown:"GCS 13-15: mild TBI. 9-12: moderate. ≤8: severe (intubation typically needed). 3 = no response in any category. Used to monitor neurological status"},
    {term:"Needle chest decompression",def:"Emergency procedure for tension pneumothorax — 14-gauge needle in 2nd intercostal space, midclavicular line",breakdown:"Rush of air confirms diagnosis. Temporary measure — chest tube (thoracostomy) needed for definitive treatment. Life-saving when performed rapidly"},
    {term:"Epinephrine in cardiac arrest",def:"1mg IV/IO every 3-5 minutes during cardiac arrest — vasoconstriction improves coronary perfusion",breakdown:"First drug in cardiac arrest algorithm. Improves return of spontaneous circulation (ROSC) but does not improve neurological outcomes. Given during compressions"},
    {term:"Amiodarone in cardiac arrest",def:"Antiarrhythmic drug for VF/pulseless VT that does not respond to defibrillation",breakdown:"300mg IV/IO first dose, 150mg second dose. Also used for stable VT and atrial fibrillation. Slows conduction, prolongs refractory period"},
    {term:"Return of spontaneous circulation (ROSC)",def:"Restoration of palpable pulse after cardiac arrest — goal of resuscitation",breakdown:"After ROSC: post-cardiac arrest care — maintain O2 sat, optimize BP, targeted temperature management (TTM), cath lab if STEMI, treat reversible causes"},
    {term:"Post-resuscitation care",def:"Care after ROSC: optimize oxygenation/ventilation, hemodynamics, treat cause, targeted temperature management",breakdown:"Target SpO2 92-98% (avoid hyperoxia). MAP >65. TTM 32-36°C if comatose. 12-lead ECG — immediate cath if STEMI. Treat hyperglycemia"},
    {term:"Blood glucose in emergencies",def:"Hypoglycemia mimics stroke/altered mental status — always check glucose in altered patients",breakdown:"'Dextrose rule': altered mental status without known cause → check glucose. BG <60 → treat immediately. Don't assume stroke until glucose ruled out"},
    {term:"Pediatric respiratory distress signs",def:"Nasal flaring, retractions (intercostal, subcostal), grunting, head bobbing, tripod position",breakdown:"Children compensate well until they crash suddenly. Retractions = increased work of breathing. Grunting = PEEP (auto-PEEP maintaining airway open). Ominous sign"},
  ]);

  fc.hard = fc.hard.concat([
    {term:"Cushing's Triad (ICP)",def:"Hypertension, bradycardia, irregular respirations — late sign of dangerously elevated intracranial pressure",breakdown:"Cushing reflex maintains cerebral perfusion as ICP rises. Treatment: osmotic therapy (mannitol, hypertonic saline), elevate HOB 30°, neurosurgical intervention"},
    {term:"Shock index",def:"Heart rate ÷ systolic BP — values >1.0 indicate significant shock; >1.7 critical",breakdown:"Normal: 60/120 = 0.5. Mild shock: 100/100 = 1.0. Significant hemorrhage: 120/80 = 1.5. Simple bedside calculation to predict need for transfusion"},
    {term:"Permissive hypotension in trauma",def:"Allowing lower BP in hemorrhaging trauma patients until surgical control — BP ~80-90 systolic",breakdown:"Excessive fluid resuscitation dilutes clotting factors, worsens hypothermia, dislodges clots. Target: SBP 80-90 for blunt trauma, 50-60 for penetrating with brain injury suspected"},
    {term:"Damage control resuscitation",def:"Hemorrhagic shock strategy: balanced blood products (1:1:1 RBC:FFP:platelets), early TXA, limit crystalloids",breakdown:"Replaces lost blood with blood components (not saline). TXA (tranexamic acid) inhibits fibrinolysis — must give within 3 hours of injury. Reduces mortality"},
    {term:"Hypothermia in trauma (lethal triad)",def:"Hypothermia + acidosis + coagulopathy — synergistic, mutually worsening, rapidly fatal",breakdown:"Hypothermia impairs clotting enzymes. Acidosis from hypoperfusion. Coagulopathy from factor dilution. Warm the patient, correct acidosis, transfuse clotting factors"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What is the first step when approaching an emergency scene?",opts:["Begin CPR","Ensure scene safety for yourself and bystanders","Call the patient's name","Check for a pulse"],correct:1,explain:"Scene safety is ALWAYS the first step. An unsafe scene can turn one victim into two or more. Look for: traffic, unstable structures, hazardous materials, violent individuals, downed power lines. If unsafe, do NOT enter — call for appropriate help."},
    {q:"What does the acronym SAMPLE stand for in patient assessment?",opts:["Signs, Allergies, Medications, Past history, Last meal, Events","Symptoms, Age, Medical history, Pain level, Level of consciousness, Emergency contacts","Scene safety, Airway, Medications, Pulse, Level of consciousness, EMS","Signs, Assessment, Management, Prevention, Lifestyle, Evaluation"],correct:0,explain:"SAMPLE: Signs/Symptoms, Allergies, Medications, Past medical history, Last oral intake (meal), Events leading to the emergency. This standardized history framework ensures no critical information is missed during patient assessment."},
    {q:"Which organization developed the 'Chain of Survival' for cardiac arrest?",opts:["HOSA","American Heart Association (AHA)","American Red Cross","National Safety Council"],correct:1,explain:"The American Heart Association (AHA) developed the Chain of Survival framework: Recognition & Activation → CPR → Defibrillation → Advanced Life Support → Post-Arrest Care → Recovery. Each link is essential for maximizing survival."},
    {q:"What is the correct position for an unconscious breathing patient?",opts:["Flat on back (supine)","Recovery position (side-lying)","Sitting upright","Face-down (prone)"],correct:1,explain:"An unconscious but breathing patient should be placed in the recovery (lateral recumbent) position — on their side with the top knee bent forward. This keeps the airway open and prevents aspiration if they vomit."},
    {q:"What is the first-line treatment for anaphylaxis?",opts:["Antihistamine (Benadryl)","Corticosteroid (prednisone)","Epinephrine (EpiPen)","Aspirin"],correct:2,explain:"Epinephrine is the ONLY first-line treatment for anaphylaxis — it counteracts vasodilation, bronchospasm, and urticaria simultaneously. Antihistamines and steroids work too slowly. Delay in epinephrine significantly increases mortality."},
    {q:"Using the Rule of Nines, what percentage of BSA does the entire head represent?",opts:["4.5%","9%","18%","1%"],correct:1,explain:"The head represents 9% of body surface area in adults using the Rule of Nines. Entire front torso = 18%, back = 18%, each arm = 9%, each leg = 18%, genitalia = 1%. Used to calculate burn extent for fluid replacement."},
    {q:"A patient is found unresponsive. You determine there is no pulse. What do you do next?",opts:["Place in recovery position","Call family members","Begin CPR and send for AED","Give two rescue breaths only"],correct:2,explain:"For an unresponsive patient with no pulse: Begin CPR immediately (start with 30 chest compressions) AND send someone for an AED. Time to defibrillation is critical — survival drops 10% for every minute of delay."},
    {q:"Which type of shock results from severe blood loss?",opts:["Cardiogenic shock","Distributive shock","Hypovolemic shock","Obstructive shock"],correct:2,explain:"Hypovolemic shock results from inadequate blood volume — caused by hemorrhage (most common in trauma), severe dehydration, burns, or severe vomiting/diarrhea. Treatment: stop bleeding, IV fluid resuscitation, blood products for hemorrhage."},
    {q:"How should you treat a first-degree burn?",opts:["Apply butter or oil","Apply ice directly","Cool with cool (not cold) water, cover loosely","Pop any blisters that form"],correct:2,explain:"First-degree burns (red, no blisters) should be cooled with cool (not ice-cold) water for 10-20 minutes. Ice can cause frostbite to damaged skin. Never apply butter, oil, or toothpaste — they trap heat and increase infection risk."},
    {q:"A patient is choking and cannot speak or cough. What should you do first?",opts:["Give abdominal thrusts immediately","Call 911 and wait for help","Give 5 back blows then 5 abdominal thrusts","Perform a finger sweep of the mouth"],correct:2,explain:"For a conscious choking adult with complete airway obstruction (cannot speak, cough, or breathe): give 5 back blows between shoulder blades, then 5 abdominal thrusts. Alternate until object dislodged or patient loses consciousness."},
    {q:"What does BE-FAST stand for in stroke recognition?",opts:["Breathing, Eyes, Face, Arms, Speech, Temperature","Balance, Eyes, Face drooping, Arm weakness, Speech difficulty, Time to call 911","Blood pressure, Eyesight, Facial palsy, Ambulance, Stroke protocol, Treatment","Breathing, Emergency, Face, Arm, Seizure, Time"],correct:1,explain:"BE-FAST: Balance (sudden loss), Eyes (sudden vision change), Face (drooping on one side), Arms (one arm drifts down), Speech (slurred or strange), Time (call 911 immediately). Updated from FAST to include Balance and Eyes for better stroke detection."},
    {q:"What is implied consent in emergency medicine?",opts:["A patient's written agreement to all emergency procedures","Assumed consent for unconscious adults in life-threatening emergencies","Consent given by another patient nearby","Permission from the patient's insurance company"],correct:1,explain:"Implied consent assumes that an unconscious or unresponsive adult in a life-threatening emergency would consent to treatment if they could. It allows emergency responders to treat patients who cannot communicate their wishes."},
    {q:"Which action is NOT appropriate during a seizure?",opts:["Time the seizure","Protect the patient's head from injury","Put something in the patient's mouth to protect their tongue","Turn patient on their side if possible"],correct:2,explain:"NEVER put anything in a seizing patient's mouth. The tongue cannot be swallowed and this action can break teeth, injure the rescuer, or block the airway. Do: time the seizure, protect the head, move dangerous objects away, turn on side if possible."},
    {q:"What should you do with a tourniquet once applied to stop life-threatening bleeding?",opts:["Remove after 10 minutes to restore circulation","Keep it on and note the time — do not remove","Loosen slightly to allow some blood flow","Remove once the patient is conscious"],correct:1,explain:"Once a tourniquet is applied and bleeding is controlled, do NOT remove it — removal can restart hemorrhage and precipitate shock. Document and communicate the time of application clearly. Surgeons will address it in the OR."},
    {q:"Heat stroke differs from heat exhaustion primarily because:",opts:["Heat stroke only affects elderly people","Heat stroke involves neurological symptoms (confusion) and temperature >104°F","Heat exhaustion is more dangerous","Heat stroke is treated with cold compresses only"],correct:1,explain:"Heat stroke is a life-threatening emergency characterized by core temperature >104°F AND neurological symptoms (confusion, slurred speech, loss of consciousness). Heat exhaustion has less severe symptoms (heavy sweating, weakness, nausea) with normal or mildly elevated temp. Rapid cooling is essential for heat stroke."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"A patient in cardiac arrest has been in VF for 2 minutes. CPR is ongoing. What is the next priority intervention?",opts:["Administer epinephrine immediately","Defibrillation with AED/defibrillator","Establish IV access","Intubate the airway"],correct:1,explain:"Defibrillation is the ONLY definitive treatment for ventricular fibrillation. It should be delivered as soon as an AED/defibrillator is available. CPR continues until the device is ready. Early defibrillation (within 3-5 minutes) dramatically improves survival."},
    {q:"Which finding would MOST suggest a tension pneumothorax?",opts:["Bilateral breath sounds, bradycardia, normal BP","Absent breath sounds on one side, tracheal deviation away from the affected side, hypotension","Bilateral crackles, elevated BP, bradycardia","Absent breath sounds bilaterally, normal BP"],correct:1,explain:"Tension pneumothorax classic signs: absent/decreased breath sounds on the affected side, tracheal deviation AWAY from the affected side, JVD (jugular venous distension), severe hypotension. Tracheal deviation is a LATE sign. Treat immediately with needle decompression."},
    {q:"A patient's GCS score is: Eyes open to voice (3) + Confused speech (4) + Withdraws to pain (4) = 11. What does this indicate?",opts:["Mild TBI — no concern","Moderate TBI — close monitoring needed","Severe TBI — immediate intervention","Normal neurological status"],correct:1,explain:"GCS 11 falls in the moderate TBI range (9-12). Mild: 13-15, Moderate: 9-12, Severe: ≤8. GCS ≤8 typically requires intubation to protect the airway. Monitor closely for deterioration — a falling GCS is a critical finding."},
    {q:"During resuscitation, when should epinephrine be given in a non-shockable rhythm (PEA or asystole)?",opts:["Only after 10 minutes of CPR","As soon as IV/IO access is established — every 3-5 minutes","Only if defibrillation fails","Not given in PEA or asystole"],correct:1,explain:"In PEA or asystole (non-shockable), epinephrine 1mg IV/IO is given as soon as access is established and then every 3-5 minutes throughout resuscitation. There is no defibrillation for non-shockable rhythms — focus is CPR + epinephrine + identifying reversible causes."},
    {q:"The Hs and Ts of cardiac arrest guide treatment of reversible causes. Which of these is a 'T'?",opts:["Hypovolemia","Hypothermia","Tension pneumothorax","Hypoxia"],correct:2,explain:"The Ts of reversible cardiac arrest causes: Tension pneumothorax, Tamponade (cardiac), Toxins (overdose/poisoning), Thrombosis (pulmonary embolism or coronary). Hypovolemia, Hypoxia, Hydrogen ion (acidosis), Hypo/Hyperkalemia, and Hypothermia are the Hs."},
    {q:"A diabetic patient is found confused and shaky. Blood glucose is 48 mg/dL. The patient is conscious. What is the appropriate treatment?",opts:["Administer IV glucagon","Give oral fast-acting carbohydrates (15-20g glucose)","Call 911 immediately and do nothing until they arrive","Administer insulin to stabilize glucose"],correct:1,explain:"For conscious hypoglycemia: give 15-20g of fast-acting carbohydrates — 4 oz juice, 3-4 glucose tablets, or regular soda. Recheck glucose in 15 minutes. Repeat if still <70. Never give insulin to a hypoglycemic patient. IV/IM glucagon is for unconscious patients."},
    {q:"What triage color indicates a patient who is deceased or has unsurvivable injuries in the START system?",opts:["Red","Yellow","Green","Black"],correct:3,explain:"In START triage: Black = deceased or unsurvivable injuries (not breathing even after airway repositioning, or catastrophic injuries). Red = immediate life threat. Yellow = delayed (serious but stable). Green = minor (walking wounded). Triage prioritizes who can benefit from immediate care with limited resources."},
    {q:"A patient has Cushing's Triad. What does this indicate and what is the primary concern?",opts:["Adrenal insufficiency — give corticosteroids","Severely elevated intracranial pressure — immediate intervention needed","Cardiac tamponade — pericardiocentesis","Hypovolemic shock — aggressive fluids"],correct:1,explain:"Cushing's Triad (hypertension + bradycardia + irregular respirations) indicates severely elevated intracranial pressure — a late and ominous sign. The brain is herniating. Immediate interventions: elevate head 30°, hyperventilation (temporary), osmotic therapy (mannitol), neurosurgical consultation."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"A trauma patient arrives with BP 70/40, HR 140, and uncontrolled abdominal hemorrhage. Which resuscitation strategy is most appropriate?",opts:["Aggressive crystalloid (normal saline) resuscitation to normalize BP","Permissive hypotension with balanced blood products (1:1:1 RBC:FFP:platelets) until surgical control","High-dose vasopressors to normalize blood pressure","Give 2L NS bolus, then reassess"],correct:1,explain:"Damage control resuscitation for hemorrhagic shock: permissive hypotension (SBP 80-90) prevents dislodging clots, balanced blood products (1:1:1) replaces what was lost, early TXA (within 3 hours) prevents fibrinolysis. Crystalloids dilute clotting factors and worsen the lethal triad (hypothermia, acidosis, coagulopathy)."},
    {q:"What is the shock index of a patient with BP 90/60 and HR 108? Is this concerning?",opts:["0.83 — within acceptable range","1.2 — significantly elevated, indicating probable shock","0.67 — normal","1.8 — immediately life-threatening"],correct:1,explain:"Shock index = HR ÷ systolic BP = 108 ÷ 90 = 1.2. Normal SI = 0.5-0.7. SI >1.0 suggests significant hemodynamic compromise. SI >1.7 is associated with high mortality. This patient needs immediate assessment for bleeding source and fluid resuscitation."},
    {q:"After successful resuscitation from cardiac arrest (ROSC), a patient is comatose. A 12-lead ECG shows STEMI. What is the priority?",opts:["Targeted temperature management (TTM) first, then cath lab in 24 hours","Immediate transfer to cardiac catheterization laboratory while initiating post-arrest care","Wait for patient to regain consciousness before invasive procedures","Repeat CPR — STEMI with coma indicates ongoing arrest"],correct:1,explain:"STEMI after ROSC requires immediate cardiac catheterization and PCI regardless of neurological status. Post-cardiac arrest STEMI care: simultaneous TTM + immediate cath lab. Evidence shows comatose ROSC patients with STEMI benefit from immediate PCI. Every minute of delay increases myocardial damage."},
  ]);
})();

// ══════════════════════════════════════════════════════════════════════════
// HEALTHY LIVING EXPANSION
// ══════════════════════════════════════════════════════════════════════════
(function expandHealthyLiving(){
  if(!window.QB_HEALTHY_LIVING) return;
  var fc = window.QB_HEALTHY_LIVING.flashcards;
  var qz = window.QB_HEALTHY_LIVING.quiz;

  fc.easy = fc.easy.concat([
    {term:"Health triangle",def:"Three dimensions of health: physical, mental/emotional, and social",breakdown:"All three must be balanced for total wellness. Neglecting one affects the others. HOSA Healthy Living tests all three dimensions"},
    {term:"Physical health",def:"The condition of the body — fitness, nutrition, sleep, avoiding harmful substances",breakdown:"Components: cardiovascular fitness, muscular strength/endurance, flexibility, body composition. Maintained through exercise and nutrition"},
    {term:"Mental health",def:"Emotional, psychological, and social well-being — how we think, feel, and handle stress",breakdown:"One in five U.S. adults experiences mental illness yearly. Just as important as physical health. Stigma remains a barrier to treatment"},
    {term:"Social health",def:"Ability to form satisfying interpersonal relationships and adapt to social situations",breakdown:"Strong social connections linked to better immune function, lower mortality, greater happiness. Loneliness is a public health crisis"},
    {term:"Aerobic exercise",def:"Sustained activity using oxygen for energy — improves cardiovascular and respiratory fitness",breakdown:"Running, swimming, cycling, walking. Recommended: 150 min/week moderate OR 75 min/week vigorous. Strengthens heart muscle, improves lung capacity"},
    {term:"Anaerobic exercise",def:"High-intensity activity using stored energy without oxygen — builds strength and muscle",breakdown:"Weight lifting, sprinting, HIIT. Builds muscle mass, increases metabolic rate, strengthens bones. Works in short intense bursts"},
    {term:"Flexibility",def:"Range of motion in joints — reduced by sedentary lifestyle and aging",breakdown:"Improved by stretching (static, dynamic, PNF). Reduces injury risk and muscle soreness. Yoga and Pilates enhance flexibility and core strength"},
    {term:"Body composition",def:"Ratio of fat mass to lean mass (muscle, bone, organs, water)",breakdown:"More meaningful than weight alone. Measured by: DEXA scan, hydrostatic weighing, BodPod, bioelectric impedance, skinfold calipers"},
    {term:"Resting heart rate",def:"Heart beats per minute at complete rest — lower = better cardiovascular fitness",breakdown:"Average adult: 60-100 bpm. Athletes: 40-60 bpm. For each beat lower, heart works more efficiently. Measure first thing in morning"},
    {term:"Target heart rate zone",def:"60-85% of maximum heart rate — optimal intensity for cardiovascular training",breakdown:"Max HR estimate: 220 - age. Age 15: max ≈ 205, target zone ≈ 123-174 bpm. Train in this zone for aerobic benefit"},
    {term:"FITT principle",def:"Frequency, Intensity, Time, Type — framework for designing effective exercise programs",breakdown:"Frequency: how often. Intensity: how hard (HR, RPE). Time: how long. Type: what kind. Manipulate these variables to progress safely"},
    {term:"Sleep hygiene",def:"Habits and practices that promote good sleep quality",breakdown:"Consistent schedule, dark/cool/quiet room, no screens 1hr before bed, avoid caffeine after 2 PM, no alcohol before bed. 8-10 hours for teens"},
    {term:"Sleep stages",def:"NREM sleep (stages 1-3) and REM sleep — cycle repeats 4-6 times per night",breakdown:"Stage 3 (deep sleep): physical restoration. REM: memory consolidation, dreaming. Disruption of either stage affects health and cognition"},
    {term:"Stress response (fight or flight)",def:"Physiological reaction to perceived threat — cortisol and adrenaline released, body prepares for action",breakdown:"Useful for actual threats. Chronic activation: hypertension, immune suppression, anxiety, weight gain. Modern stressors rarely require fight or flight"},
    {term:"Cortisol",def:"Primary stress hormone released by adrenal glands — elevated chronically with chronic stress",breakdown:"Short-term: raises blood glucose, suppresses digestion, sharpens alertness. Chronic: increases belly fat, weakens immune system, disrupts sleep"},
    {term:"Mindfulness",def:"Present-moment awareness without judgment — reduces stress and improves mental health",breakdown:"Mindfulness-based stress reduction (MBSR): clinically proven to reduce anxiety, depression, pain. Apps: Calm, Headspace. 8-week MBSR program standard"},
    {term:"Substance abuse",def:"Pattern of using substances (alcohol, drugs, tobacco) causing significant harm or impairment",breakdown:"Not the same as dependence/addiction. Substance use disorder diagnosed when use significantly impairs daily functioning. 21 million Americans affected"},
    {term:"Nicotine addiction",def:"Physical and psychological dependence on nicotine — highly addictive chemical in tobacco",breakdown:"Nicotine reaches brain in 7-10 seconds. Releases dopamine — reward pathway. Withdrawal: irritability, anxiety, cravings. Smoking cessation doubles over cold turkey"},
    {term:"Alcohol and brain development",def:"Alcohol significantly damages developing brains — adolescents especially vulnerable",breakdown:"Prefrontal cortex develops until age 25. Alcohol impairs memory, impulse control, and learning. Teens who drink before 15 are 4x more likely to develop alcohol dependency"},
    {term:"Immunization",def:"Administration of vaccine to stimulate immune response and provide protection from disease",breakdown:"Herd immunity: when enough of population is immune to protect those who cannot be vaccinated. Threshold varies: measles 95%, polio 80-85%"},
    {term:"Infectious disease transmission",def:"Direct: contact, droplet, sexual. Indirect: airborne, vector, fomite, fecal-oral",breakdown:"Droplet: stays <3 feet (flu). Airborne: stays suspended (COVID, TB, measles). Fomite: contaminated surface. Vector: mosquito, tick"},
    {term:"Hand hygiene",def:"Most effective infection prevention — wash 20 seconds with soap or use 60%+ alcohol sanitizer",breakdown:"WHO 5 moments: before patient contact, before aseptic procedure, after body fluid exposure, after patient contact, after touching patient environment"},
    {term:"Sun protection",def:"SPF 30+ sunscreen, reapply every 2 hours, UV-protective clothing — prevents skin cancer",breakdown:"UV radiation causes 99% of non-melanoma skin cancers. SPF 30 blocks 97% of UVB. Must reapply after swimming/sweating. Most common cancer in U.S."},
    {term:"Dental health",def:"Brush 2x daily with fluoride toothpaste, floss daily, regular dental cleanings",breakdown:"Oral bacteria linked to cardiovascular disease, diabetes complications. Fluoride strengthens enamel. Gum disease affects 47% of adults 30+"},
    {term:"Screen time effects",def:"Excessive screen time linked to poor sleep, depression, anxiety, sedentary behavior",breakdown:"Blue light suppresses melatonin — disrupts sleep. Social media comparison increases depression rates. AAP: teens limit recreational screen time, prioritize sleep"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"Metabolic syndrome",def:"Cluster of conditions: abdominal obesity, hypertension, high blood glucose, abnormal cholesterol",breakdown:"Having 3 of 5 criteria = metabolic syndrome. Dramatically increases cardiovascular disease and type 2 diabetes risk. Affects 1 in 3 Americans"},
    {term:"Hypertension stages",def:"Normal: <120/80. Elevated: 120-129/<80. Stage 1 HTN: 130-139/80-89. Stage 2 HTN: ≥140/90",breakdown:"Hypertension: 'silent killer' — no symptoms until organ damage. First-line: lifestyle changes. Stage 2: medication usually needed. Damages heart, kidneys, brain, eyes"},
    {term:"Diabetes types",def:"Type 1: autoimmune destruction of beta cells. Type 2: insulin resistance + relative insulin deficiency. Gestational: during pregnancy",breakdown:"T1: requires insulin. T2: often manageable with lifestyle + oral meds → insulin. Prediabetes (HbA1c 5.7-6.4%): reversible with lifestyle changes"},
    {term:"Cardiovascular risk factors",def:"Modifiable: smoking, inactivity, poor diet, obesity, hypertension, diabetes, high cholesterol. Non-modifiable: age, sex, genetics",breakdown:"Modifiable risk factors are the target of prevention programs. Framingham Risk Score calculates 10-year CVD risk from risk factors"},
    {term:"Body mass index limitations",def:"BMI doesn't measure body fat directly — can misclassify muscular athletes as overweight",breakdown:"Alternative measures: waist circumference (>40in men, >35in women = increased risk), waist-to-hip ratio, body fat percentage. BMI is population screening tool"},
    {term:"Sleep and immune function",def:"Sleep deprivation reduces cytokine production and immune cell activity — increases infection susceptibility",breakdown:"<7 hours/night: 3x more likely to develop cold when exposed. Sleep during illness: fever increases cytokine production and immune effectiveness"},
    {term:"Mental health conditions prevalence",def:"Anxiety disorders: most common (18%). Depression: 8%. Eating disorders: 5-10%. Schizophrenia: 1%",breakdown:"50% of mental illness begins by age 14. Average 11-year delay between onset and first treatment. Early intervention dramatically improves outcomes"},
    {term:"Cognitive behavioral therapy (CBT)",def:"Evidence-based therapy challenging negative thought patterns and behaviors — first-line for anxiety, depression",breakdown:"Identifies cognitive distortions (catastrophizing, all-or-nothing thinking). Teaches reframing. More effective than medication alone for many conditions"},
    {term:"Exercise and mental health",def:"150 min/week of moderate exercise reduces depression risk by 30%, anxiety by 48%",breakdown:"Exercise: releases endorphins, serotonin, BDNF (brain growth factor). As effective as antidepressants for mild-moderate depression. Free, no side effects"},
    {term:"Health behavior change models",def:"Transtheoretical Model (stages of change): Precontemplation → Contemplation → Preparation → Action → Maintenance",breakdown:"People don't change immediately — they progress through stages. Interventions should match stage. Motivational interviewing helps move through stages"},
    {term:"Healthy People 2030",def:"National health promotion and disease prevention objectives set by DHHS every decade",breakdown:"500+ objectives covering leading causes of disease and disability. Current focus: health equity, social determinants, mental health, substance use, COVID recovery"},
    {term:"Cancer prevention behaviors",def:"No tobacco, limit alcohol, sun protection, healthy weight, physical activity, screening, vaccination",breakdown:"HPV vaccine prevents cervical, throat, and other cancers. Screening: mammogram, colonoscopy, Pap smear, lung CT for smokers. 40% of cancers preventable"},
    {term:"Overtraining syndrome",def:"Excessive training without adequate recovery — causes performance decline, fatigue, mood changes, injury",breakdown:"Signs: persistent fatigue, decreased performance, resting HR increase, sleep disruption, frequent illness. Treatment: rest, recovery, nutrition. Prevent by periodization"},
    {term:"RICE method (injury)",def:"Rest, Ice, Compression, Elevation — first aid for acute musculoskeletal injuries",breakdown:"Updated to PRICE (Protection) or POLICE (Optimal Loading). Ice for 20min/hour. Compression reduces swelling. Elevation above heart level. Seek care if severe"},
    {term:"Eating disorders",def:"Mental illnesses with abnormal eating behaviors — anorexia nervosa, bulimia nervosa, binge eating disorder, ARFID",breakdown:"Highest mortality of any mental illness. Anorexia: restriction, severe underweight. Bulimia: binge-purge. BED: binge without purging. ARFID: avoidant/restrictive"},
  ]);

  fc.hard = fc.hard.concat([
    {term:"Epigenetics and lifestyle",def:"Lifestyle factors can alter gene expression without changing DNA sequence — reversible",breakdown:"Exercise, diet, stress, sleep, toxin exposure alter methylation patterns. Father's obesity before conception affects offspring metabolism. Some changes heritable"},
    {term:"Telomere length and aging",def:"Telomeres shorten with each cell division and stress — shorter = biological aging. Lifestyle affects rate",breakdown:"Chronic stress, poor sleep, smoking accelerate telomere shortening. Exercise, Mediterranean diet, mindfulness slow shortening. Nobel Prize 2009 (Blackburn, Greider, Szostak)"},
    {term:"Gut-brain axis",def:"Bidirectional communication between gut microbiome and brain — affects mood, cognition, behavior",breakdown:"90% of serotonin produced in gut. Gut bacteria produce neurotransmitters. Dysbiosis (imbalanced microbiome) linked to depression, anxiety, autism spectrum disorder"},
    {term:"Hormetic stress",def:"Low-dose stress that triggers adaptive response stronger than the original stressor — 'what doesn't kill you makes you stronger'",breakdown:"Exercise: muscle damage → stronger muscles. Intermittent fasting: cellular autophagy. Cold exposure: mitochondrial biogenesis. Dose and recovery are critical"},
    {term:"Allostatic load",def:"Cumulative burden of chronic stress and life events on the body — measurable physiological wear",breakdown:"Measured by: cortisol, blood pressure, waist-hip ratio, inflammation markers, HbA1c. High allostatic load predicts disease, cognitive decline, premature death"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What are the three dimensions of the health triangle?",opts:["Physical, mental, and spiritual","Physical, mental/emotional, and social","Physical, academic, and social","Nutritional, physical, and emotional"],correct:1,explain:"The health triangle consists of three equal dimensions: physical health (body), mental/emotional health (mind), and social health (relationships). All three must be in balance for total wellness. Neglecting one dimension affects the others."},
    {q:"How many minutes per week of moderate aerobic exercise do health guidelines recommend for adults?",opts:["60 minutes","90 minutes","150 minutes","300 minutes"],correct:2,explain:"Health guidelines recommend at least 150 minutes of moderate-intensity aerobic exercise per week (or 75 minutes of vigorous activity). This can be broken into 30-minute sessions, 5 days per week. Additional benefits at 300 minutes/week."},
    {q:"Which type of exercise primarily improves cardiovascular fitness?",opts:["Anaerobic exercise","Flexibility training","Aerobic exercise","Resistance training"],correct:2,explain:"Aerobic exercise (running, swimming, cycling) primarily improves cardiovascular and respiratory fitness by strengthening the heart, improving lung capacity, and increasing oxygen delivery to muscles. Anaerobic exercise primarily builds strength and muscle mass."},
    {q:"What does the FITT principle stand for?",opts:["Flexibility, Intensity, Timing, Training","Frequency, Intensity, Time, Type","Fitness, Interval, Time, Technique","Frequency, Interval, Training, Tension"],correct:1,explain:"FITT = Frequency (how often), Intensity (how hard), Time (how long), Type (what kind of exercise). These four variables are manipulated to design effective, progressive exercise programs that avoid plateau and overtraining."},
    {q:"How many hours of sleep do teenagers (14-17) need per night?",opts:["6-7 hours","7-8 hours","8-10 hours","10-12 hours"],correct:2,explain:"Teenagers aged 14-17 need 8-10 hours of sleep per night. The developing brain requires extra sleep for growth hormone release, memory consolidation, emotional regulation, and physical development. Most teens are chronically sleep-deprived."},
    {q:"Which of the following is an example of a mental health strategy?",opts:["Taking vitamin supplements","Mindfulness meditation","Drinking energy drinks","Avoiding all social interaction"],correct:1,explain:"Mindfulness meditation is an evidence-based mental health strategy — it reduces anxiety, depression, and stress by training present-moment awareness. Other mental health strategies include therapy (CBT), exercise, social connection, journaling, and adequate sleep."},
    {q:"What is the most effective action for preventing the spread of infectious disease?",opts:["Wearing a mask at all times","Taking antibiotics preventively","Proper hand washing for 20 seconds","Avoiding all public places"],correct:2,explain:"Proper hand hygiene — washing with soap and water for at least 20 seconds (or using 60%+ alcohol sanitizer) — is the single most effective way to prevent spread of most infectious diseases. It removes pathogens from the skin before they can be transferred to mucous membranes."},
    {q:"Which behavior is MOST associated with reducing cancer risk?",opts:["Eating red meat daily","Avoiding tobacco use","Drinking orange juice daily","Sleeping more than 10 hours"],correct:1,explain:"Tobacco avoidance is the single most impactful cancer prevention behavior — smoking causes about 30% of all cancer deaths. Other key behaviors: healthy weight, physical activity, limiting alcohol, sun protection, cancer screenings, and HPV/Hepatitis B vaccination."},
    {q:"What does sun protection factor (SPF) 30 indicate?",opts:["Protects skin for 30 minutes only","Blocks approximately 97% of UVB rays","Provides 30 times more protection than SPF 1","Is only needed at SPF 50 or higher"],correct:1,explain:"SPF 30 blocks approximately 97% of UVB rays. SPF 50 blocks 98%. No sunscreen blocks 100%. Reapply every 2 hours and after swimming or sweating. Use broad-spectrum (UVA + UVB) SPF 30+ daily."},
    {q:"Chronic stress primarily causes long-term harm through which mechanism?",opts:["Causing immediate organ failure","Prolonged elevation of cortisol and adrenaline that damages body systems","Reducing appetite completely","Eliminating the immune response"],correct:1,explain:"Chronic stress causes prolonged elevation of cortisol and adrenaline. Long-term effects include: hypertension, weakened immune system, increased abdominal fat, sleep disruption, anxiety, depression, and increased cardiovascular risk. Acute stress is beneficial; chronic stress is harmful."},
    {q:"What is herd immunity?",opts:["When all animals in a herd are vaccinated","When enough of a population is immune to prevent disease spread to unprotected individuals","Immunity that develops from herding cattle","Natural immunity that develops after infection"],correct:1,explain:"Herd immunity occurs when enough of a population is immune (through vaccination or prior infection) that the disease cannot spread efficiently, protecting those who cannot be vaccinated (infants, immunocompromised). The threshold varies: measles requires 95% immunity."},
    {q:"Which of the following best describes the health benefit of regular physical activity for mental health?",opts:["Reduces the need for sleep","Releases endorphins and neurotransmitters that reduce depression and anxiety","Eliminates the need for mental health treatment","Only benefits mental health in elite athletes"],correct:1,explain:"Regular physical activity releases endorphins, serotonin, and BDNF (brain-derived neurotrophic factor) — chemicals that improve mood, reduce anxiety, and protect against depression. Studies show 150 min/week reduces depression risk by 30% and is as effective as antidepressants for mild-moderate depression."},
    {q:"What is the primary health risk associated with excessive alcohol consumption by adolescents?",opts:["It causes immediate liver failure","It disrupts brain development since the brain develops until age 25","It primarily affects physical fitness","It has no unique risks for teens compared to adults"],correct:1,explain:"Adolescent brains are still developing until age 25 — alcohol is especially damaging during this critical period. Teen drinking impairs memory, impulse control, and decision-making. Teens who drink before age 15 are 4x more likely to develop alcohol use disorder."},
    {q:"According to the FITT principle, changing which variable would improve cardiovascular fitness in an intermediate exerciser?",opts:["Type: switching from running to playing cards","Frequency: adding one more workout day per week","Time: reducing workout duration","Intensity: exercising at 20% max heart rate"],correct:1,explain:"Adding frequency (an extra workout day) is an appropriate progression for an intermediate exerciser. Increasing intensity (higher HR zone) or time are also valid. Reducing time or intensity would cause regression. Playing cards is not aerobic exercise."},
    {q:"The 'fight or flight' response is controlled primarily by which system?",opts:["Digestive system","Immune system","Sympathetic nervous system","Parasympathetic nervous system"],correct:2,explain:"The sympathetic nervous system triggers the fight-or-flight response — releasing adrenaline (epinephrine) and cortisol, increasing heart rate and blood pressure, dilating airways, redirecting blood to muscles. The parasympathetic system controls 'rest and digest.'"},
  ]);

  qz.medium = qz.medium.concat([
    {q:"A 16-year-old's maximum heart rate is estimated to be 204 bpm. What is their aerobic training zone?",opts:["102-143 bpm","122-173 bpm","163-184 bpm","60-80 bpm"],correct:1,explain:"Max HR = 220 - 16 = 204 bpm. Aerobic training zone = 60-85% of max HR. 60%: 204 × 0.60 = 122.4 bpm. 85%: 204 × 0.85 = 173.4 bpm. Training at 122-173 bpm provides optimal cardiovascular benefit."},
    {q:"Metabolic syndrome is diagnosed when a patient has three or more of which criteria?",opts:["Underweight, low blood pressure, low cholesterol, high HDL, low blood glucose","Abdominal obesity, hypertension, high triglycerides, low HDL, high fasting blood glucose","High protein intake, low carbohydrate intake, high physical activity, low sleep, high stress","Overweight BMI, low vitamin D, high iron, low calcium, elevated WBC"],correct:1,explain:"Metabolic syndrome is diagnosed with 3+ of: (1) waist >40in men/>35in women, (2) triglycerides ≥150, (3) HDL <40mg/dL men/<50 women, (4) BP ≥130/85, (5) fasting glucose ≥100mg/dL. Dramatically increases CVD and diabetes risk."},
    {q:"A student sleeps 5 hours per night during the school week. Which health consequences are MOST likely?",opts:["Improved academic performance from more study time","Impaired memory consolidation, increased cortisol, weakened immune function, increased depression risk","No significant health effects if they 'catch up' on weekends","Only physical health effects, not mental health effects"],correct:1,explain:"Chronic sleep deprivation (teens need 8-10 hours) causes: impaired memory and learning (REM sleep consolidates memory), elevated cortisol (stress response), weakened immunity (cytokine production drops), increased depression and anxiety risk, and poor impulse control. Weekend catch-up sleep partially compensates but doesn't fully restore."},
    {q:"Which stage of the Transtheoretical Model describes a person who knows they need to exercise more but isn't doing anything about it yet?",opts:["Precontemplation","Contemplation","Preparation","Action"],correct:1,explain:"Contemplation: the person is aware of the problem and considering change but hasn't committed to action. Precontemplation: not yet aware or not considering change. Preparation: making plans to change. Action: actively changing behavior (within 6 months). Maintenance: sustaining change >6 months."},
    {q:"Which intervention has the STRONGEST evidence for treating mild to moderate depression?",opts:["Vitamin supplements alone","Regular aerobic exercise combined with cognitive behavioral therapy","Elimination of all sugar from diet","Complete social isolation to reduce stimulation"],correct:1,explain:"The combination of regular aerobic exercise and CBT (cognitive behavioral therapy) has the strongest evidence base for treating mild to moderate depression. Exercise alone is as effective as antidepressants for many patients. CBT addresses thought patterns. Together they address both biological and psychological dimensions."},
    {q:"What distinguishes overtraining syndrome from normal exercise fatigue?",opts:["Overtraining fatigue resolves after one rest day; normal fatigue persists for weeks","Overtraining causes persistent performance decline, mood changes, and elevated resting HR despite rest","Overtraining only affects professional athletes","Normal fatigue is always more severe than overtraining"],correct:1,explain:"Overtraining syndrome (OTS) causes persistent fatigue, decreased performance, elevated resting heart rate, mood disturbances, frequent illness, and sleep disruption that do NOT resolve with short rest. It requires weeks to months of reduced training. Prevented by periodization (planned recovery cycles)."},
    {q:"HPV vaccination is recommended primarily because it prevents which diseases?",opts:["HIV and hepatitis","Cervical cancer and other HPV-related cancers and genital warts","All sexually transmitted infections","Breast cancer and prostate cancer"],correct:1,explain:"HPV vaccine prevents cancers caused by human papillomavirus — primarily cervical cancer but also vaginal, vulvar, penile, anal, and oropharyngeal (throat) cancers, plus genital warts. Gardasil 9 covers 9 HPV strains responsible for 90% of HPV cancers. Recommended at age 11-12."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"Research shows a strong link between gut microbiome and mental health. Which statement best explains this relationship?",opts:["Gut bacteria directly control all emotions through the bloodstream","The gut-brain axis allows bidirectional communication — gut bacteria produce neurotransmitters and send signals via the vagus nerve affecting mood and cognition","Gut health only affects physical health, not mental health","The relationship is theoretical and not clinically relevant yet"],correct:1,explain:"The gut-brain axis involves bidirectional signaling between the enteric nervous system (gut) and central nervous system (brain) via the vagus nerve, immune system, and bacterial metabolites. Gut bacteria produce 90% of the body's serotonin. Dysbiosis (microbiome imbalance) is associated with depression, anxiety, and cognitive changes."},
    {q:"Epigenetic research suggests which lifestyle implications?",opts:["Genetics alone determine health outcomes — lifestyle is irrelevant","Lifestyle factors (diet, exercise, stress, sleep) alter gene expression without changing DNA — these changes can be reversed and some are heritable","Only medications can alter gene expression","Epigenetic changes happen randomly and cannot be influenced"],correct:1,explain:"Epigenetics shows that lifestyle factors alter gene expression through DNA methylation and histone modification — without changing the DNA sequence. These changes are often reversible (exercise reverses stress-induced methylation changes) and some are transmitted to offspring. This is why lifestyle interventions can counteract genetic predispositions."},
    {q:"What is allostatic load and how is it clinically useful?",opts:["A single blood test measuring overall health status","The cumulative biological burden of chronic stress measured across multiple physiological systems — predicts disease and mortality","A measure of how much exercise someone can handle","The amount of cortisol in the bloodstream at any given time"],correct:1,explain:"Allostatic load quantifies the cumulative wear on the body from chronic stress across multiple biomarkers: cortisol levels, blood pressure, waist-hip ratio, inflammatory markers (IL-6, CRP), HbA1c, and lipids. High allostatic load predicts cardiovascular disease, cognitive decline, immune dysfunction, and all-cause mortality — more accurately than any single biomarker."},
  ]);
})();

// ══════════════════════════════════════════════════════════════════════════
// VETERINARY SCIENCE EXPANSION
// ══════════════════════════════════════════════════════════════════════════
(function expandVeterinary(){
  if(!window.QB_VETERINARY) return;
  var fc = window.QB_VETERINARY.flashcards;
  var qz = window.QB_VETERINARY.quiz;

  fc.easy = fc.easy.concat([
    {term:"Veterinarian (DVM/VMD)",def:"Doctor of Veterinary Medicine — diagnoses and treats animal diseases, performs surgery",breakdown:"4-year veterinary school after bachelor's. Specialties: small animal, large animal, exotic, zoo, public health, research, military"},
    {term:"Veterinary technician (RVT/CVT)",def:"Licensed professional assisting veterinarians — similar to RN for humans",breakdown:"2-4 year program + national board exam (VTNE). Performs lab tests, administers medications, assists surgery, takes radiographs"},
    {term:"Veterinary assistant",def:"Entry-level veterinary team member — animal care, restraint, cleaning, client communication",breakdown:"On-the-job training or short certificate program. Does not perform medical procedures. Growing demand in veterinary settings"},
    {term:"Zoonotic disease",def:"Infectious disease transmissible between animals and humans",breakdown:"Examples: rabies, Lyme disease, salmonella, ringworm, toxoplasmosis, COVID-19 (SARS-CoV-2 originated in animals). One Health concept"},
    {term:"One Health",def:"Concept recognizing human, animal, and environmental health are interconnected and interdependent",breakdown:"Shared by CDC, WHO, and USDA. Zoonoses, antimicrobial resistance, food safety, climate change are One Health issues"},
    {term:"Rabies",def:"Fatal viral zoonosis transmitted through infected animal saliva — affects nervous system",breakdown:"Reservoir hosts: bats, raccoons, skunks, foxes. 99% of human cases from dog bites in developing world. Post-exposure prophylaxis (PEP) is effective. Vaccine all pets"},
    {term:"Canine anatomy — dogs",def:"Carnivore digestive system: short intestine, sharp teeth, no amylase in saliva",breakdown:"4 canine (fang) teeth. Stomach can hold large meals (evolved as feast-famine hunters). Panting = thermoregulation (no sweat glands on body)"},
    {term:"Feline anatomy — cats",def:"Obligate carnivores — cannot survive without animal protein (taurine essential)",breakdown:"Retractable claws. Righting reflex allows landing on feet. Purring: 25-150 Hz vibrations with healing properties. Jacobson's organ for pheromone detection"},
    {term:"Equine anatomy — horses",def:"Herbivore with unique hindgut fermentation; sensitive GI tract prone to colic",breakdown:"Single-toed (hoof = modified middle finger). Sleep standing using stay apparatus. 10-gallon stomach — must eat frequently. Largest domesticated animal"},
    {term:"Bovine anatomy — cattle",def:"Ruminants with 4-compartment stomach: rumen, reticulum, omasum, abomasum",breakdown:"Rumen: fermentation chamber — bacteria break down cellulose. Regurgitate and rechew cud. Produce methane (significant greenhouse gas)"},
    {term:"Ruminant",def:"Even-toed ungulate that digests plant-based food by chewing cud — cattle, sheep, goats, deer",breakdown:"4-compartment stomach allows cellulose digestion (humans cannot). Rumen bacteria produce volatile fatty acids used for energy. Require high-fiber diets"},
    {term:"Vital signs (dogs)",def:"Temperature: 99.5-102.5°F, Pulse: 60-140 bpm, Respiration: 10-30 breaths/min",breakdown:"Larger dogs have slower HR than small dogs. Normal dog temp range same as cats. Respiration varies with activity, anxiety, temperature"},
    {term:"Vital signs (cats)",def:"Temperature: 99.5-102.5°F, Pulse: 120-200 bpm, Respiration: 20-30 breaths/min",breakdown:"Cats have faster HR than dogs. Feline temperature same range as canine. Cats often stress at vet — white coat syndrome increases HR and temp"},
    {term:"Anesthesia (veterinary)",def:"Drug-induced unconsciousness for surgery — includes induction agent + inhaled maintenance agent",breakdown:"Propofol or ketamine for induction. Isoflurane/sevoflurane inhaled for maintenance. Monitoring: HR, SpO2, capnography, blood pressure, temperature"},
    {term:"Rabies vaccine",def:"Core vaccine for all dogs and cats — legally required in most jurisdictions",breakdown:"Given at 12-16 weeks, 1 year later, then every 1-3 years depending on product. State laws require vaccination. Non-core vaccines based on risk"},
    {term:"Core vaccines (dogs)",def:"DHPP: Distemper, Hepatitis (Adenovirus), Parainfluenza, Parvovirus + Rabies",breakdown:"Given as combo vaccine (DA2PP or DHPP). Puppy series: 8, 12, 16 weeks. Boosted 1 year, then every 3 years. Rabies per local law"},
    {term:"Core vaccines (cats)",def:"FVRCP: Feline Viral Rhinotracheitis, Calicivirus, Panleukopenia + Rabies",breakdown:"Panleukopenia: highly contagious, often fatal — feline distemper. Kitten series: 8, 12, 16 weeks. Rabies required by law"},
    {term:"Spay (ovariohysterectomy)",def:"Surgical removal of female animal's ovaries and uterus — prevents reproduction and disease",breakdown:"Eliminates pyometra risk (uterine infection), reduces mammary cancer risk 91% if done before first heat. Most common veterinary surgery"},
    {term:"Neuter (castration)",def:"Surgical removal of male animal's testes — prevents reproduction, reduces certain behaviors",breakdown:"Reduces roaming, aggression, marking, prostate disease. Eliminates testicular cancer. Done at 6 months in dogs/cats (earlier possible)"},
    {term:"Microchipping",def:"Implanting a RFID chip under pet's skin — permanent identification, recovers lost pets",breakdown:"Injected between shoulder blades. 15-digit ISO standard number. Owner registers in database. 20x more likely to reunite with lost pet"},
    {term:"Flea lifecycle",def:"Egg → Larva → Pupa → Adult — 95% of flea population is in the environment, not on the pet",breakdown:"Adult fleas on pet = 5% of total infestation. Must treat environment AND all pets. Pupae resistant to insecticides. Full lifecycle: 2 weeks - 6 months"},
    {term:"Heartworm disease",def:"Parasitic worms (Dirofilaria immitis) transmitted by mosquitoes — live in heart and pulmonary arteries",breakdown:"Dogs: main host. Cats: atypical host, fewer worms but more severe. Prevention: monthly medication. Treatment in dogs: slow kill (melarsomine). No treatment for cats"},
    {term:"Parvovirus (canine)",def:"Highly contagious, potentially fatal viral infection — attacks rapidly dividing cells (GI tract, bone marrow)",breakdown:"Signs: severe bloody vomiting and diarrhea, lethargy, anemia, death without treatment. Survives in environment >1 year. Unvaccinated puppies most vulnerable"},
    {term:"Animal restraint",def:"Safe physical or chemical handling of animals to prevent injury to animal and handler",breakdown:"Fear-free approach: minimize stress through gentle handling, calming techniques, pheromones. Restraint should be minimum necessary. Muzzles for safety when needed"},
    {term:"Microorganism identification in veterinary lab",def:"Gram stain: differentiates bacteria (gram+ purple vs gram- pink). Culture identifies specific organism",breakdown:"Gram-positive: thick peptidoglycan wall (Staph, Strep). Gram-negative: thin wall with outer membrane (E. coli, Salmonella). Different antibiotic sensitivity"},
  ]);

  fc.medium = fc.medium.concat([
    {term:"Antimicrobial resistance (AMR)",def:"Microorganisms evolve to resist antibiotics — significant One Health concern",breakdown:"Veterinary antibiotic use contributes to AMR in human pathogens. MRSA, MRSP (Staphylococcus pseudintermedius). Prudent use critical: culture before treating"},
    {term:"MRSA in veterinary medicine",def:"Methicillin-resistant Staphylococcus aureus — can transfer between humans and companion animals",breakdown:"Reverse zoonosis: humans infect pets, pets infect humans. Veterinary staff at higher risk. Contact precautions, hand hygiene critical. Treat underlying cause"},
    {term:"Feline urological syndrome (FLUTD)",def:"Group of conditions affecting feline lower urinary tract — straining to urinate, blood in urine, urethral obstruction",breakdown:"Male cats especially prone to urethral obstruction ('blocked cat') — emergency. Causes: crystals, stones, idiopathic cystitis. Moist food diet reduces risk"},
    {term:"Diabetes in pets",def:"Type 1-like in dogs (require insulin). Type 2-like in cats (may resolve with diet + insulin)",breakdown:"Signs: polyuria, polydipsia, weight loss despite eating. Treated with insulin injections. Cats: often responds to low-carbohydrate diet + insulin. Monitor glucose and fructosamine"},
    {term:"Cushing's disease (hyperadrenocorticism)",def:"Excess cortisol production — most common endocrine disorder in dogs",breakdown:"Signs: pot-belly, hair loss, increased appetite/thirst, muscle wasting, skin changes. Pituitary-dependent (85%) or adrenal tumor (15%). Treatment: trilostane or mitotane"},
    {term:"Hypothyroidism in dogs",def:"Deficiency of thyroid hormone — most common endocrine disorder in dogs",breakdown:"Signs: weight gain, lethargy, hair loss, cold intolerance. Diagnosed by T4 level. Treatment: lifetime levothyroxine supplementation. Not seen commonly in cats (hyperthyroid more common in cats)"},
    {term:"Hyperthyroidism in cats",def:"Excess thyroid hormone production — most common endocrine disorder in middle-aged to older cats",breakdown:"Signs: weight loss despite increased appetite, hyperactivity, heart disease, hypertension, vomiting. Treatment: radioactive iodine (curative), methimazole, surgical thyroidectomy, prescription diet"},
    {term:"Anesthesia monitoring",def:"Continuous assessment during surgical anesthesia — HR, SpO2, ETCO2, blood pressure, temperature",breakdown:"ETCO2 (end-tidal CO2): confirms correct tube placement, monitors ventilation. SpO2 < 95% is concerning. Temperature drops rapidly in anesthetized patients — warming devices essential"},
    {term:"Veterinary dentistry",def:"Most common disease in pets: periodontal disease — affects 80% of dogs and 70% of cats over age 3",breakdown:"Bacteria spread from mouth to heart, kidneys, liver. Professional cleaning under anesthesia. Home brushing prevents plaque buildup. Annual dental exam important"},
    {term:"Pain assessment in animals",def:"Animals hide pain — behavioral changes: lethargy, aggression, posture changes, decreased appetite",breakdown:"Pain scales: Colorado State Feline Acute Pain Scale, Glasgow Composite Pain Scale. Pre-emptive analgesia better than treating established pain. Multimodal analgesia preferred"},
    {term:"Feline infectious peritonitis (FIP)",def:"Progressive, usually fatal disease caused by feline coronavirus mutation",breakdown:"Two forms: wet (effusions in chest/abdomen) and dry (granulomas in organs). Primarily affects young cats. New antiviral (GS-441524) shows 80%+ cure rate — expensive but transformative"},
    {term:"Distemper in dogs",def:"Viral disease affecting GI, respiratory, and nervous systems — often fatal",breakdown:"Highly contagious airborne virus. Signs: fever, discharge, coughing, neurological signs. No specific antiviral — supportive care. Core vaccine prevents. Raccoons also susceptible"},
    {term:"Food animal medicine",def:"Veterinary care for cattle, pigs, sheep, goats, poultry — production and welfare focused",breakdown:"Large animal practitioners do herd-level medicine. Focus: production diseases, reproductive management, food safety, biosecurity, welfare audits"},
    {term:"Necropsy",def:"Post-mortem examination of an animal — analogous to human autopsy",breakdown:"Gross and histopathologic examination to determine cause of death. Essential for flock/herd disease investigation. State labs perform on wildlife and food animals"},
    {term:"Veterinary public health",def:"Application of veterinary skills to protect and improve human and animal population health",breakdown:"USDA food inspectors are veterinarians. Epidemiologists investigating zoonotic outbreaks. Military working dog veterinarians. Laboratory research veterinarians. Biosecurity for bioterrorism response"},
  ]);

  fc.hard = fc.hard.concat([
    {term:"Sepsis in veterinary patients",def:"Life-threatening systemic inflammatory response to infection — requires aggressive treatment",breakdown:"Signs: fever or hypothermia, tachycardia, tachypnea, altered mentation. SIRS + suspected infection = sepsis. Treatment: IV fluids, broad-spectrum antibiotics, vasopressors if needed"},
    {term:"Disseminated intravascular coagulation (DIC)",def:"Pathological clotting throughout vasculature with simultaneous bleeding — consumptive coagulopathy",breakdown:"DIC = 'Death Is Coming' — grave prognosis. Triggered by: sepsis, neoplasia, trauma, envenomation. Uses up clotting factors (bleeding) + forms microthrombi (organ failure)"},
    {term:"Toxicology — common pet toxins",def:"Dogs: grapes/raisins, xylitol (sugar-free gum), chocolate, NSAIDs, rodenticide. Cats: lilies (fatal), NSAIDs, acetaminophen",breakdown:"Grapes: 1 grape can cause acute renal failure in dogs. Xylitol: causes hypoglycemia and liver failure. Lilies (all parts) cause feline renal failure within 72 hours — no antidote"},
    {term:"Rodenticide toxicity (anticoagulant)",def:"Inhibits vitamin K epoxide reductase — blocks production of clotting factors — internal hemorrhage",breakdown:"Brodifacoum, bromadiolone: second-generation. Half-life weeks — treated with vitamin K for weeks. Relay toxicity: pets eating poisoned rodents. Signs delayed 2-7 days"},
    {term:"Shock treatment in veterinary patients",def:"IV fluid bolus (crystalloids or colloids) + identify and treat cause + vasopressors if unresponsive",breakdown:"Crystalloids (LRS, normal saline): 10-20 mL/kg bolus dogs, 10 mL/kg cats. Colloids (Hetastarch, albumin): smaller volume needed. Measure and monitor response continuously"},
  ]);

  qz.easy = qz.easy.concat([
    {q:"What does 'zoonotic disease' mean?",opts:["Disease only found in zoo animals","Infectious disease transmissible between animals and humans","Disease affecting multiple animal species but not humans","A disease requiring quarantine at a zoo"],correct:1,explain:"Zoonotic diseases are infectious diseases that can be transmitted between animals and humans. Examples include rabies, Lyme disease (tick-borne), salmonella, ringworm, toxoplasmosis, and even COVID-19 (which originated from animals). This is why veterinary and human medicine intersect."},
    {q:"What is the 'One Health' concept?",opts:["The idea that all pets should receive identical medical care","The recognition that human, animal, and environmental health are interconnected","A vaccination program for one specific disease","A veterinary care plan for one animal"],correct:1,explain:"One Health recognizes that the health of humans, animals, and the environment are fundamentally interconnected. Zoonotic diseases, antimicrobial resistance, food safety, and environmental health issues require collaboration between human medicine, veterinary medicine, and environmental science."},
    {q:"What is the most common route of rabies transmission to humans?",opts:["Contact with infected animal feces","Scratch from infected animal","Bite from infected animal transmitting saliva","Inhaling air near infected bats"],correct:2,explain:"Rabies is most commonly transmitted through the bite of an infected animal, which introduces infected saliva into the wound. Post-exposure prophylaxis (PEP) — rabies immune globulin plus vaccine — is effective if given promptly after exposure."},
    {q:"Dogs are classified as which type of eater?",opts:["Obligate carnivores","Herbivores","Omnivores","Insectivores"],correct:2,explain:"Dogs are omnivores — they can digest and utilize nutrients from both animal and plant sources. This differs from cats, which are obligate carnivores (must eat animal protein). Dogs have more amylase than cats, allowing better starch digestion."},
    {q:"Cattle have how many compartments in their stomach?",opts:["1","2","3","4"],correct:3,explain:"Ruminants like cattle have a 4-compartment stomach: rumen (fermentation chamber), reticulum (honeycomb texture, catches debris), omasum (water absorption), and abomasum (true stomach, acid digestion). This allows digestion of cellulose-rich plant material."},
    {q:"What does a spay surgery involve?",opts:["Removal of the male animal's testes","Removal of the female animal's ovaries and uterus","Placement of a microchip","Removal of the animal's dewclaws"],correct:1,explain:"A spay (ovariohysterectomy) is the surgical removal of a female animal's ovaries and uterus. It permanently prevents reproduction and significantly reduces the risk of pyometra (uterine infection) and mammary (breast) cancer."},
    {q:"Which disease is in the core vaccine series for dogs (DHPP)?",opts:["Leptospirosis","Lyme disease","Parvovirus","Giardia"],correct:2,explain:"DHPP stands for Distemper, Hepatitis (Adenovirus), Parainfluenza, and Parvovirus — all core vaccines for dogs. Rabies is also core. Leptospirosis and Lyme are non-core (given based on risk). Parvovirus is especially dangerous for unvaccinated puppies."},
    {q:"What is heartworm disease and how is it transmitted?",opts:["Intestinal parasites spread by fleas","Parasitic worms in the heart and arteries transmitted by mosquito bites","A viral heart disease spread by tick bites","A bacterial heart infection from contaminated food"],correct:1,explain:"Heartworm (Dirofilaria immitis) is transmitted through mosquito bites. Larvae grow into worms up to 12 inches long living in the heart and pulmonary arteries. Prevention (monthly medication) is far safer and cheaper than treatment. Dogs, cats, and ferrets can be affected."},
    {q:"What is the normal rectal temperature range for both dogs and cats?",opts:["97-99°F","99.5-102.5°F","103-105°F","95-97°F"],correct:1,explain:"Normal rectal temperature for both dogs and cats is 99.5-102.5°F (37.5-39.2°C). Temperatures above 103°F indicate fever. Above 105°F is a medical emergency. Rectal temperature is most accurate; ear and forehead readings are less reliable in animals."},
    {q:"What percentage of a flea infestation lives OFF the pet (in the environment)?",opts:["5%","25%","50%","95%"],correct:3,explain:"95% of a flea infestation (eggs, larvae, pupae) lives in the environment (carpet, bedding, yard) — only 5% (adult fleas) lives on the pet. This is why treating the pet alone is insufficient — you must also treat the environment to break the flea lifecycle."},
    {q:"What is microchipping in pets?",opts:["Implanting GPS tracking in the brain","Subcutaneous implantation of an RFID chip for permanent identification","A type of surgical monitoring device","A chip that dispenses medication"],correct:1,explain:"A microchip is a tiny RFID (radio frequency identification) device implanted under the skin between the shoulder blades. Each chip has a unique 15-digit number linked to owner information in a registry database. Microchipped pets are 20x more likely to be reunited with owners if lost."},
    {q:"Which disease primarily affects the intestinal tract and bone marrow of unvaccinated puppies?",opts:["Distemper","Rabies","Parvovirus","Leptospirosis"],correct:2,explain:"Canine parvovirus attacks rapidly dividing cells — primarily the GI tract (causing severe bloody vomiting and diarrhea) and bone marrow (causing immunosuppression). It is highly contagious and can be fatal without aggressive treatment. Vaccination is the most effective prevention."},
  ]);

  qz.medium = qz.medium.concat([
    {q:"A cat presents with straining to urinate, crying in the litter box, and no urine production for 24 hours. What is the most likely emergency?",opts:["Bladder infection (UTI)","Feline urethral obstruction ('blocked cat') — life-threatening emergency","Constipation","Kidney stones requiring surgery in 1 week"],correct:1,explain:"Urethral obstruction ('blocked cat') is a life-threatening emergency — the urethra is obstructed (crystals, mucus plug, or spasm), preventing urine outflow. Without treatment, cats die from uremia and hyperkalemia within 24-48 hours. Requires immediate urethral catheterization and hospitalization. Male cats are most susceptible due to narrow urethra."},
    {q:"The One Health approach would be MOST applicable to investigating which scenario?",opts:["A dog with a broken leg","An outbreak of Salmonella infections in humans traced to contaminated poultry","A cat with dental disease","A horse with a respiratory infection on a single farm"],correct:1,explain:"One Health is most applicable to the Salmonella outbreak — it involves the intersection of animal health (poultry), human health (infected people), and environmental health (food processing facilities). Investigation requires collaboration between veterinarians, public health officials, and environmental scientists."},
    {q:"Antimicrobial resistance is a One Health concern because:",opts:["Only animals can develop resistance","Antibiotic use in veterinary medicine can select for resistant bacteria that transfer to humans","Resistance only occurs with human antibiotic use","Animals and humans have completely separate bacterial populations"],correct:1,explain:"Antibiotic use in food animals and pets selects for resistant bacteria that can transfer to humans through direct contact, food, or environmental routes. MRSA is documented passing between humans and pets. This is why veterinary antimicrobial stewardship — using antibiotics prudently and only when necessary — is a critical One Health issue."},
    {q:"A dog with Cushing's disease presents with pot-belly, hair loss, increased thirst, and muscle weakness. What is the underlying mechanism?",opts:["Insufficient thyroid hormone","Excess cortisol production from pituitary or adrenal abnormality","Insulin deficiency","Excess growth hormone"],correct:1,explain:"Cushing's disease (hyperadrenocorticism) results from excess cortisol — most commonly from a pituitary tumor causing excess ACTH production (85% of cases) or from an adrenal tumor (15%). Chronic excess cortisol causes all the classic signs: pot-belly (fat redistribution), muscle wasting, PU/PD, hair loss, and immunosuppression."},
    {q:"Why do cats get hyperthyroidism while dogs more commonly get hypothyroidism?",opts:["It is a coincidence with no biological explanation","Cats have overactive immune systems; dogs have underactive thyroid glands","Cats tend to develop thyroid tumors (adenomas) causing excess hormone; dogs tend to have autoimmune thyroid destruction causing deficiency","Dogs eat more iodine than cats"],correct:2,explain:"In cats, hyperthyroidism is almost always caused by benign thyroid adenomas producing excess T4. In dogs, hypothyroidism typically results from autoimmune lymphocytic thyroiditis or idiopathic atrophy destroying the thyroid gland. These are distinct diseases with different mechanisms, not just opposite versions of the same condition."},
    {q:"What is the clinical significance of periodontal disease in pets beyond the mouth?",opts:["There is no systemic significance — it only affects teeth","Bacteria from periodontal infection can spread via bloodstream to heart valves, kidneys, and liver — causing systemic disease","Periodontal disease only affects very old animals","The only risk is tooth loss"],correct:1,explain:"Periodontal disease allows bacteria to continuously enter the bloodstream (bacteremia) from inflamed gums. These bacteria can damage heart valves (endocarditis), kidneys, and liver over time. This is why dental care is considered essential preventive medicine, not cosmetic. 80% of dogs and 70% of cats over 3 have some degree of periodontal disease."},
  ]);

  qz.hard = qz.hard.concat([
    {q:"A dog is brought in after ingesting an unknown rodenticide 3 days ago. Lab work shows a markedly prolonged PT/PTT but normal platelet count. What is the most likely toxin and treatment?",opts:["Zinc phosphide — treat with IV fluids","Anticoagulant rodenticide (brodifacoum) — treat with oral vitamin K1 for 4+ weeks","Strychnine — treat with muscle relaxants","Metaldehyde — treat with activated charcoal"],correct:1,explain:"Anticoagulant rodenticides (especially second-generation brodifacoum) inhibit vitamin K epoxide reductase, blocking synthesis of clotting factors II, VII, IX, X. Signs appear 2-7 days after ingestion (when existing factors are depleted). Treatment: oral vitamin K1 for 4-6 weeks (duration matches toxin half-life). Relay toxicity occurs when pets eat poisoned rodents."},
    {q:"A cat presents collapsed with pale mucous membranes and a heart rate of 60 bpm. Bloodwork shows severe hyperkalemia and azotemia. The most likely cause is:",opts:["Severe dehydration","Urethral obstruction causing post-renal uremia and life-threatening hyperkalemia","Hypovolemic shock from hemorrhage","Addison's disease (hypoadrenocorticism)"],correct:1,explain:"Urethral obstruction causes urine to back up, leading to: azotemia (waste product accumulation), hyperkalemia (K+ cannot be excreted — causes dangerous bradycardia and cardiac arrhythmias), and metabolic acidosis. Treatment is urgent: IV fluids, cardiac monitoring, urethral catheterization, and medical stabilization before anesthesia for catheter placement."},
    {q:"Which statement best describes the veterinarian's role in antimicrobial stewardship?",opts:["Prescribe the broadest-spectrum antibiotic to ensure treatment success","Reserve all antibiotics for human use only","Culture and sensitivity testing before prescribing, use narrowest effective spectrum, complete full courses, report resistance patterns","Antibiotics are safe for long-term use so resistance concerns are overstated"],correct:2,explain:"Veterinary antimicrobial stewardship: perform culture and sensitivity testing to identify the pathogen and its susceptibilities, select the narrowest effective antibiotic (avoiding critically important antibiotics when alternatives exist), dose correctly, complete full courses, and participate in resistance surveillance. This reduces selection pressure for resistant organisms that can transfer to humans."},
  ]);
})();
